package simple

import (
	"context"
	"math/rand"
	"time"

	agv "github.com/Kerrigan-Automation/overmind/public/lib/fm/agv"
	plugin "github.com/Kerrigan-Automation/overmind/public/lib/script/go_plugin"
	agvpb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/conveyance/mobile/agv"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/config"

	"github.com/Kerrigan-Automation/overmind/public/lib/retry"
)

/////////////////////////////////////////////////////////////////////////////////////////////////////
//
// NB: this script is not intended as a production script and only a demonstration. It is important to
// consider Pause (takes us to the start of the same step) and Stop (takes us to beginning of the cycle)
// and to design the script to be able to handle these (either by figuring a way for how to continue,
// or worst case Alarm'ing and requesting assistance)
//
/////////////////////////////////////////////////////////////////////////////////////////////////////

var cfg_agv001 = &Config{
	Description: "AGV001: wp2 -> wp8 -> wp2 loop, via operate",
	AgvId:       agv.AgvId("001"),
	SequenceConfig: plugin.SequencerConfig[*script]{
		Steps: []*plugin.SequencerStep[*script]{
			{
				Name:        "check_lease",
				Description: "check if I have a lease on agv",
				Stages: []*plugin.SequencerStepStage[*script]{
					conditionalAgvLeased("get_lease", "is_agv_loaded"),
				},
			},
			{
				Name:        "get_lease",
				Description: "lease agv 001",
				Stages: []*plugin.SequencerStepStage[*script]{
					getAgvLeaseStageFabric(agv.AgvId("001")),
				},
			},
			{
				Name:        "is_agv_loaded",
				Description: "check if agv 001 is loaded",
				Stages: []*plugin.SequencerStepStage[*script]{
					conditionalAgvLoadedState("move_to_load_request", "move_to_unload_request"),
				},
			},
			{
				Name:        "move_to_load_request",
				Description: "get agv 001 to wp8, load",
				Stages: []*plugin.SequencerStepStage[*script]{
					operateAgvToWaypointStage(agv.AgvId("001"), "wp8", &agvpb.PayloadOpRequest{
						PayloadOpType: agvpb.PayloadOpType_PAYLOAD_OP_TYPE_LOAD,
						BayName:       agv.BayIdDefault.String(),
					}),
				},
				Cancel: releaseMyLeasesForCancelFabric,
			},
			{
				Name:        "move_to_load_confirm",
				Description: "confirm agv 001 moves to wp8, load",
				Stages: []*plugin.SequencerStepStage[*script]{
					waitOnAgvOperateOutcomeStage("Agv001ToWp8", time.Second*360),
				},
				Cancel: releaseMyLeasesForCancelFabric,
			},
			{
				Name:        "move_to_unload_request",
				Description: "get agv 001 to wp2, unload",
				Stages: []*plugin.SequencerStepStage[*script]{
					operateAgvToWaypointStage(agv.AgvId("001"), "wp2", &agvpb.PayloadOpRequest{
						PayloadOpType: agvpb.PayloadOpType_PAYLOAD_OP_TYPE_UNLOAD,
						BayName:       agv.BayIdDefault.String(),
					}),
				},
				Cancel: releaseMyLeasesForCancelFabric,
			},
			{
				Name:        "move_to_unload_confirm",
