					waitOnAgvOperateOutcomeStage("Agv001ToWp2", time.Second*360),
				},
				Cancel: releaseMyLeasesForCancelFabric,
			},
			// ... more to come...
			{
				Name:        "release_lease",
				Description: "release agv 001 lease",
				Stages: []*plugin.SequencerStepStage[*script]{
					releaseMyAgvLeaseStageFabric(agv.AgvId("001")),
				},
				Cancel: releaseMyLeasesForCancelFabric,
			},
			{
				Name:        "wait_for_MES_next_cycle_request",
				Description: "random wait to simulate MES delay (max 5s)",
				Stages: []*plugin.SequencerStepStage[*script]{
					randomWait(time.Second * 5),
				},
			},
		},
		RecentSteps: 10,
		Iterations:  plugin.IterateForever,
		Backoff:     retry.DefaultExponentialBackoffConfig(),
