func randomWait(wait time.Duration) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "randomWait",
		Op: func(ctx context.Context, s *script) error {
			select {
			case <-ctx.Done():
				return nil
			case <-time.After(time.Duration(rand.Int63n(int64(wait)))):
				// pretend we wait some amount before we get the next job from MES.
				return nil
			}
		},
	}
}

