package simple

import (
	"context"
	"errors"
	"fmt"
	"slices"
	"time"

	agv "github.com/Kerrigan-Automation/overmind/public/lib/fm/agv"
	plugin "github.com/Kerrigan-Automation/overmind/public/lib/script/go_plugin"
	"github.com/Kerrigan-Automation/overmind/public/lib/eidns"
	access "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/conveyance/mobile/agv_manager"
	agvpb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/conveyance/mobile/agv"
	agv_managerpb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/conveyance/mobile/agv_manager"
	instancepb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/escript/instance"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/commands"
	configpb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/config"

	"go.uber.org/zap"
)

func operateAgvToWaypointStage(agvId agv.AgvId, wp string, payloadOp *agvpb.PayloadOpRequest) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: fmt.Sprintf("move%sTo%s", agvId.String(), wp),
		Op: func(ctx context.Context, s *script) error {

			s.waitingOnJob = ""
			s.entityIds = []*configpb.EntityKindAndName{
				s.eidNs.NewEntityKindAndName(configpb.EntityKind_ENTITY_KIND_AGV, agvId.String()),
				s.eidNs.NewEntityKindAndName(configpb.EntityKind_ENTITY_KIND_NODE, wp),
			}

			// Fabric client - this will allow us to access fabric.
			client := s.svc.FabricClient()
			// Target ID for Agv - we make a core EntityId out of the AgvId. core EntityId is the AGV identity from the
			// global namespace of possible entities discussed over fabric.
			targetId := eidns.NewAgvEid(s.eidNs, agvId.String())

			// Get a common command which will have unique ID. We will use this to track result for our operation
			cr := access.NewCommandRequest()

			ctx, cancel := context.WithTimeout(ctx, time.Second*5)
			defer cancel()
			reqResult, err := agv_manager.OperateLeasedAgvRequest(ctx, client,
				&agv_managerpb.OperateAgvRequest{
					CommandRequest: cr,
					Requestor:      s.svc.MyScriptId(),
					Command: &agv_managerpb.AgvCommand{
						WaypointId:       wp,
						PayloadOpRequest: payloadOp, // operation once at waypoint if required.
					},
				},
				access.RequestWithTarget(targetId))
			if err != nil {
				// return error and retry (this is likely communications failure.)
				s.logger.Error("failed to operate agv, OperateLeasedAgvRequest returned an error", zap.Error(err))
				return err
			}

			if reqResponse, reqerr := reqResult.Await(ctx); reqerr != nil {
				// return error and retry (this is likely communications failure.)
				s.logger.Error("failed to operate agv, Await returned an error", zap.Error(err))
				return reqerr
			} else {
				cr := reqResponse.Response.GetCommandResponse()
				if cr.GetOutcome() == commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_FAILURE {
					err := errors.New(cr.GetDescription())
					if reqResponse.Response.GetResponseCode() == agv_managerpb.OpResponseCode_OP_RESPONSE_CODE_AGV_NOT_LEASED {
						// We appear to have lost out lease. This probably means an operator intervened to take control. Losing the lease
						// means we need to start our cycle from scratch.
						err = fmt.Errorf("%s no longer holds lease for %s: %v", s.svc.MyScriptId(), agvId.String(), err)
						s.logger.Error("failed to operate agv", zap.Error(err))
						return plugin.NewErrRestartScriptCycle(err)
					}
					s.logger.Error("failed to operate agv, response included an error", zap.Error(err))
					return err //retry
				}
			}

			s.waitingOnJob = cr.GetId()
			s.updateActiveStepWithReason(plugin.StepReason{
				Reason: "accepted",
			}, instancepb.StepStatus_STEP_STATUS_EXECUTING, true)
			return nil
		},
	}
}

// conditionalAgvLoadedState checks if tracked agv is loaded and if so, directs cycle to loadedStep, otherwise goes to
// unloadedStep
func conditionalAgvLoadedState(loadStep, unloadStep string) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "conditionalAgvLoadedState",
		Op: func(ctx context.Context, s *script) error {

			// relevant entities for reporting purposes only (published in script instance step report)
			s.entityIds = []*configpb.EntityKindAndName{
				s.eidNs.NewEntityKindAndName(configpb.EntityKind_ENTITY_KIND_AGV, s.cfg.AgvId.String()),
			}
			first := true
			agvState, _ := s.agvStateTracker.State()
			for ctx.Err() == nil {
				if !first {
					// wait for subsequent update
					agvState, _ = s.agvStateTracker.WaitForUpdate(ctx)
				}
				first = false
				if agvState == nil {
					// we are not seeing any state at all... we will wait for next update.
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason: "no_active_state",
					}, instancepb.StepStatus_STEP_STATUS_EXECUTING, false)
					continue // wait for next update or being stopped
				}

				bays := agvState.GetState().GetBays()
				for _, bay := range bays {
					if bay.GetOccupied() { // this script is interested in at least one loaded bay. If loaded we skip to unload step.
						s.updateActiveStepWithReason(plugin.StepReason{
							Reason:  "agv_loaded",
							Context: map[string]any{"next_step": unloadStep},
						}, instancepb.StepStatus_STEP_STATUS_EXECUTING, true)
						return plugin.NewErrRestartScriptStepByName(fmt.Errorf("agv loaded, skip to unload step"), unloadStep, s.seq)
					}
				}
				// agv is unloaded, move to load step
				s.updateActiveStepWithReason(plugin.StepReason{
					Reason:  "agv_unloaded",
					Context: map[string]any{"next_step": loadStep},
				}, instancepb.StepStatus_STEP_STATUS_EXECUTING, true)
				return plugin.NewErrRestartScriptStepByName(fmt.Errorf("agv unloaded, skip to load step"), loadStep, s.seq)
			}

			return ctx.Err()
		},
	}
}

// waitOnAgvOperateOutcomeStage waits for a terminal state on command with id 'waitingOnJob'. If `maxTimeToCommandReport`
// is set and passes without progress (i.e. no updates with the command in non terminal state), then we give up. As long as
// we see updates with active command we do not give up (unless some higher layer cancels the context).
func waitOnAgvOperateOutcomeStage(step string, maxTimeToCommandReport time.Duration) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: fmt.Sprintf("waitOnJobId%s", step),
		Op: func(ctx context.Context, s *script) error {
			eventsShowingCommand := 0
			eventsNotShowingCommand := 0
			first := true

			// if we were paused times starts afresh. This is the earliest we could have received a progress report in this
			// iteration.
			since := time.Now()

			// in here we simply loop and wait for the agv to get to the state we want it to.
			acs, origin := s.agvControlTracker.State()
			for ctx.Err() == nil {
				// if we got this far, we think AGV is not yet in the right state... so we wait...
				if !first {
					// stop and wait for next update
					if maxTimeToCommandReport > 0 {
						ctxWithMaxDuration, cancel := context.WithTimeout(ctx, maxTimeToCommandReport)
						acs, origin = s.agvControlTracker.WaitForUpdate(ctxWithMaxDuration)
						cancel()
					} else {
						acs, origin = s.agvControlTracker.WaitForUpdate(ctx)
					}

				}
				first = false

				if maxTimeToCommandReport > 0 && time.Since(since) > maxTimeToCommandReport {
					return plugin.NewErrRestartScriptCycle(
						fmt.Errorf("job %s failed, agv controller not reported progress in '%v'", s.waitingOnJob, maxTimeToCommandReport))
				}

				if acs == nil {
					// we are not seeing any state at all... we will wait for next update.
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason: "no_state",
					}, instancepb.StepStatus_STEP_STATUS_EXECUTING, false)
					continue
				}

				cr, err := getCommandInstance(acs, s.waitingOnJob)
				if err == nil {
					// our command is being reported on... reset timer
					since = time.Now()
					eventsShowingCommand++
					if cr.CommandInstance.State == commands.CommandState_COMMAND_STATE_COMPLETED_SUCCESSFULLY {
						// defer update, because we are just about to close step - last update to leave on job.
						s.updateActiveStepWithReason(plugin.StepReason{
							Reason: "agv_op_succeeded",
						}, instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
						// job done!
						return nil
					} else if cr.CommandInstance.State == commands.CommandState_COMMAND_STATE_FAILED {
						// job failed!
						return plugin.NewErrRestartScriptCycle(fmt.Errorf("job %s failed, agv controller reports '%s'", s.waitingOnJob, cr.CommandInstance.GetDetail()))
					} else {
						// a pending update...
						s.updateActiveStepWithReason(plugin.StepReason{
							Reason: "job_update",
							Context: map[string]any{
								"state":  cr.CommandInstance.GetState().String(),
								"detail": cr.CommandInstance.GetDetail(),
							},
						}, instancepb.StepStatus_STEP_STATUS_EXECUTING, false)
					}
				} else {
					// we will make this more sophisticated. We are not seeing our command reported on as neither
					// active nor recently completed. We will wait on the basis that we expect to see outcome of
					// our request. We will need to deal with recovering from not seeing it. e.g. do we see
					// the derside outcome? Have we waited too long etc.
					if eventsNotShowingCommand%10 == 0 {
						// every 10 updates, we update detail script to show we are getting events but still
						// no sign of our command.
						s.updateActiveStepWithReason(plugin.StepReason{
							Reason: "agv_controller_report_missing",
							Context: map[string]any{
								"seen":        eventsShowingCommand,
								"unseen":      eventsNotShowingCommand,
								"last_origin": origin,
							},
						}, instancepb.StepStatus_STEP_STATUS_EXECUTING, false)
					}
					eventsNotShowingCommand++
				}

			}

			return ctx.Err()
		},
	}
}

// update the active step status of the script.
func (s *script) updateActiveStepWithReason(reason plugin.StepReason, status instancepb.StepStatus, deferNotification bool) {
	reasonStr := reason.String()
	s.psp.UpdateState(func(state *instancepb.State, detailed *instancepb.VerboseState) (plugin.UpdateType, error) {

		// add tags from exported state of agv control? e.g. path. Let's see if we need it gives 'reason' may
		// contain enough. deferNotification tells us we do not need to indicate change because caller knows
		// we are going to issue an update anyway (e.g. closing step, closing cycle). We use deferNotification
		// to shortcircuit change comparison, and to force update in return.

		fs := detailed.ActiveSteps[0]
		if fs != nil {
			update := false

			if deferNotification || fs.Status != status || fs.Reason != reasonStr {
				fs.Status = status
				fs.Reason = reasonStr
				update = true
			}
			if s.waitingOnJob != "" && (deferNotification || !slices.Contains(fs.JobIds, s.waitingOnJob)) {
				fs.JobIds = []string{s.waitingOnJob}
				update = true
			}

			// we track entity ids but don't issue update just because of entityid changes. We may tighten this
			// in future to check for changes herre.
			fs.EntityIds = s.entityIds

			if update && !deferNotification {
				return plugin.UpdateTypeOnlyDetailed, nil
			}
		}
		return plugin.UpdateTypeNone, nil
	})
}

// conditionalAgvLeased checks if tracked agv is leased by me
func conditionalAgvLeased(stepToGetLease, stepIdLeased string) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "conditionalAgvLeased",
		Op: func(ctx context.Context, s *script) error {

			// relevant entities for reporting purposes only (published in script instance step report)
			s.entityIds = []*configpb.EntityKindAndName{
				s.eidNs.NewEntityKindAndName(configpb.EntityKind_ENTITY_KIND_AGV, s.cfg.AgvId.String()),
			}
			// leasedTo me
			leasedTo := s.svc.MyScriptId()

			first := true
			ctrlState, _ := s.agvControlTracker.State()
			for ctx.Err() == nil {
				if !first {
					// wait for subsequent update from AGV controller
					ctrlState, _ = s.agvControlTracker.WaitForUpdate(ctx)
				}
				first = false
				if ctrlState == nil {
					// we are not seeing any state at all... we will wait for next update.
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason: "no_active_state",
					}, instancepb.StepStatus_STEP_STATUS_EXECUTING, false)
					continue // wait for next update or being stopped
				}

				if lease := ctrlState.GetLease(); lease != nil && lease.GetTo() == leasedTo {
					// we have the lease, move to the appropriate next step, and also make sure we show up in the leased
					// adjs we are tracking.
					s.leasedAgvs[s.cfg.AgvId] = true
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason:  "leased",
						Context: map[string]any{"next_step": stepIdLeased},
					}, instancepb.StepStatus_STEP_STATUS_EXECUTING, true)
					return plugin.NewErrRestartScriptStepByName(fmt.Errorf("AGV is leased to me, skip to next step"), stepIdLeased, s.seq)
				} else {
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason:  "not_leased",
						Context: map[string]any{"next_step": stepToGetLease},
					}, instancepb.StepStatus_STEP_STATUS_EXECUTING, true)
					delete(s.leasedAgvs, s.cfg.AgvId)
					return plugin.NewErrRestartScriptStepByName(fmt.Errorf("agv not leased to me, skip to load step"), stepToGetLease, s.seq)
				}
			}

			return ctx.Err()
		},
	}
}

var (
	ErrAgvControlStateNil      = errors.New("agv control state is nil")
	ErrCommandInstanceNotFound = errors.New("command instance not found")
)

// getCommandInstance finds the command record for a give instance.
func getCommandInstance(acs *agv_managerpb.AgvControlState, commandId string) (*agv_managerpb.CommandRecord, error) {
	if acs == nil {
		return nil, ErrAgvControlStateNil
	}

	if acs.ActiveCommand != nil &&
		acs.GetActiveCommand().GetCommandInstance().GetRequest().GetId() == commandId {
		return acs.GetActiveCommand(), nil
	}

	for _, cr := range acs.GetRecentCommands() {
		if cr.GetCommandInstance().GetRequest().GetId() == commandId {
			return cr, nil
		}
	}
	return nil, ErrCommandInstanceNotFound
}

// getAgvLeaseStageFabeic creates a sequencer step stage that leases a specific agv over fabric
func getAgvLeaseStageFabric(agvId agv.AgvId) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "leaseAgv",
		Op: func(ctx context.Context, s *script) error {

			// lease requests are sent tot he AgvManager
			targetId := eidns.NewAgvManagerEid(s.eidNs)
			// Fabric client - this will allow us to access fabric.
			client := s.svc.FabricClient()
			// leasedTo me
			leasedTo := s.svc.MyScriptId()

			req := &agv_managerpb.LeaseAgvRequest{
				LeasedTo:       leasedTo,
				CommandRequest: access.NewCommandRequest(),
				MandatedAgvIds: []string{agvId.String()},
			}
			result, err := agv_manager.GetLeaseOnAgvRequest(
				ctx,
				client,
				req,
				access.RequestWithTarget(targetId))
			if err != nil {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv on request %s: %w", agvId.String(), err))
			}

			response, err := result.Await(ctx)
			if err != nil {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv on await %s: %w", agvId.String(), err))
			}

			r := response.Response
			cr := r.GetCommandResponse()
			if cr.GetOutcome() != commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_ACCEPTED {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv %s, %s", agvId.String(), cr.GetDescription()))
			}

			if r.GetAgvId() == "" {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv %s, no agv id returned", agvId.String()))
			}

			// for reporting purposes only, we also record the AGV in the active job
			s.psp.UpdateFirstActiveJob(func(j *instancepb.StepReport) (plugin.UpdateType, error) {
				j.EntityIds = append(
					j.EntityIds, s.eidNs.NewEntityKindAndName(configpb.EntityKind_ENTITY_KIND_AGV, agvId.String()))
				// defer immediate update given we're about to return nil closing the step (which will automatically update)
				return plugin.UpdateTypeNone, nil
			})

			leasedAgv := r.GetAgvId()
			s.leasedAgvs[agv.AgvId(leasedAgv)] = true

			return nil
		},
	}
}

// releases a lease for a specific AGV. This can be called on cancellation or at the end of an operation.
func releaseMyAgvLeaseFabric(ctx context.Context, s *script, agvId agv.AgvId) error {
	// release leases

	// lease requests are sent tot he AgvManager
	targetId := eidns.NewAgvManagerEid(s.eidNs)
	// Fabric client - this will allow us to access fabric.
	client := s.svc.FabricClient()
	// leasedTo me
	leasedTo := s.svc.MyScriptId()

	request := &agv_managerpb.ReturnLeaseAgvRequest{
		CommandRequest: access.NewCommandRequest(),
		AgvId:          agvId.String(),
		LeasedTo:       leasedTo,
	}

	result, err := agv_manager.ReturnLeaseOnAgvRequest(ctx, client, request, access.RequestWithTarget(targetId))
	if err != nil {
		return err
	}

	response, err := result.Await(ctx)
	if err != nil {
		return err
	}

	r := response.Response.GetCommandResponse()
	if r.GetOutcome() != commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_ACCEPTED {
		err := fmt.Errorf("failed to release lease for %s: %s", agvId.String(), r.GetOutcome().String())

		return plugin.NewErrRestartScriptStep(err)
	}

	// stop tracking it...
	delete(s.leasedAgvs, agvId)

	return nil
}

// releases all leases held by this script. Cancel is a oneshot affair (typically when things are not going to plan)
// We use Cancel to try and leave the world as good a place as possible. We should (still) assume as little as possible
// on the way up (e.g. a script which releases its leases on cancel, may still release all its leases at the start
// of a cycle.)
func releaseMyLeasesForCancelFabric(ctx context.Context, s *script, err error) {
	for agvId := range s.leasedAgvs {
		releaseMyAgvLeaseFabric(ctx, s, agvId)
	}
}

func releaseMyAgvLeaseStageFabric(agvId agv.AgvId) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "releaseAgv",
		Op: func(ctx context.Context, s *script) error {

			found := false
			for leasedAgv := range s.leasedAgvs {
				if leasedAgv == agvId {
					found = true
					break
				}
			}
			if !found {
				return nil
			}

			if err := releaseMyAgvLeaseFabric(ctx, s, agvId); err != nil {
				return err
			}
			// for reporting purposes only, we also record the AGV in the active job
			s.psp.UpdateFirstActiveJob(func(j *instancepb.StepReport) (plugin.UpdateType, error) {
				j.Reason = "successfully released AGV lease" // example use of Reason on success
				j.EntityIds = append(
					j.EntityIds, s.eidNs.NewEntityKindAndName(configpb.EntityKind_ENTITY_KIND_AGV, agvId.String()))
				return plugin.UpdateTypeNone, nil
			})

			return nil
		},
	}
}

