package simple

import (
	"context"
	"sync"

	agv "github.com/Kerrigan-Automation/overmind/public/lib/fm/agv"
	plugin "github.com/Kerrigan-Automation/overmind/public/lib/script/go_plugin"
	"github.com/Kerrigan-Automation/overmind/public/lib/eidns"
	agvspec "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/conveyance/mobile/agv"
	agv_managerspec "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/conveyance/mobile/agv_manager"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/escript/instance"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/config"
	"github.com/cenkalti/backoff/v5"

	"github.com/machinebox/graphql"
	"go.uber.org/zap"
	"google.golang.org/protobuf/types/known/timestamppb"
)

func (cfg *Config) Configure(ctx context.Context, wg *sync.WaitGroup, svc plugin.HostServices) (plugin.ScriptPlugin, error) {
	defer wg.Done()

	// Start up stopped. The safest possible way. This may have to change to reflect previous activated state.
	initDesired := &instance.ControlRequest{
		RequestedMode: instance.Mode_MODE_STOPPED,
	}
	initState := &instance.State{
		// NOTE that we do inject Name, BootedAt directly. These are injected by the host since the host know these
		// if we do not set them. (If we did set them they would not be overwritten)
		ActiveMode:     instance.Mode_MODE_STOPPED,
		RequestedMode:  instance.Mode_MODE_STOPPED,
		RequestedOn:    timestamppb.Now(),
		TransitionedOn: timestamppb.Now(),
	}

	// pullScriptPlugin allows script to manage tags and detailed tags on reported state if necessary.
	// It is also handed to sequencer to allow sequencer to honour control requests from overming.
	psp := plugin.NewPullScriptPlugin(initState, initDesired, svc, cfg.CycleBuckets, cfg.StepBuckets)

	// publish a short description tag for operators
	psp.UpdateState(func(state *instance.State, verbose *instance.VerboseState) (plugin.UpdateType, error) {
		desc := cfg.Description
		if desc == "" {
			desc = "simple sequencer loop"
		}
		t := state.Tags
		if t == nil {
			t = &config.TagSet{}
		}
		t.Tags = append(t.Tags, &config.Tag{Key: "description", Value: desc})
		state.Tags = t
		return plugin.UpdateTypeIncludesCore, nil
	})
	sequencer, err := plugin.NewSequencer(cfg.SequenceConfig, psp, svc)
	if err != nil {
		return nil, err
	}

	// set up script with the ability to map to global namespace for identities.
	eidNs := svc.EidNs()

	// get fabric or gql client or both, and whatever other systems we need to interact with in
	// the sequencer step operations we provide. Whatever we put in script is made available in
	// the callbacks.
	gqlClient, err := svc.GqlClient()
	if err != nil {
		return nil, err
	}

	script := &script{
		cfg:        cfg,
		seq:        sequencer,
		svc:        svc,
		psp:        psp,
		eidNs:      eidNs,
		gqlClient:  gqlClient,
		leasedAgvs: make(map[agv.AgvId]bool),
		logger:     svc.Logger(),
	}

	// We are going to watch the AGV controller updates. We will be working with the AGV so we
	// want to follow outcome of our requests. We follow the AGV vontroller, and the AGV itself
	// (currently to decide whether to load or unload based on loaded state).
	wg.Add(1)
	script.agvControlTracker, err = agv_managerspec.NewTrackAgvControlState(
		ctx, wg, svc.FabricClient(), eidns.NewAgvEid(eidNs, cfg.AgvId.String()), cfg.Backoff)
	if err != nil {
		return nil, err
	}

	wg.Add(1)
	script.agvStateTracker, err = agvspec.NewTrackActiveState(
		ctx, wg, svc.FabricClient(), eidns.NewAgvEid(eidNs, cfg.AgvId.String()), cfg.Backoff)
	if err != nil {
		return nil, err
	}

	wg.Add(1)
	go sequencer.Runner(ctx, wg, script)

	return psp, nil
}

// script tracks context made available to every callback in steps.
type script struct {
	cfg          *Config
	seq          *plugin.Sequencer[*script]
	svc          plugin.HostServices
	psp          *plugin.PullScriptPlugin
	eidNs        *eidns.EidNsManager
	gqlClient    *graphql.Client
	waitingOnJob string
	// Watch the AGV's controller and AGV state updates.
	agvControlTracker *agv_managerspec.TrackedAgvControlState
	agvStateTracker   *agvspec.TrackedActiveState
	leasedAgvs        map[agv.AgvId]bool
	// entity Ids tracks the fm components pertinent to a cycle
	entityIds []*config.EntityKindAndName
	logger    *zap.Logger
}

type Config struct {
	// Short description published as a tag for operators
	Description string
	// K/V which are meaningful to me, the script writer. I get to see this in UI. And when
	// at the ui, I collect details state from script I will also see the detailed KV.
	Tags         config.TagSet
	DetailedTags config.TagSet
	// sequencer configuration - we put all the sequence steps we want to implement in here.
	SequenceConfig plugin.SequencerConfig[*script]
	// metrics buckets used to determine histogram buckets for duration metrics of cycles and steps.
	Backoff      *backoff.ExponentialBackOff
	CycleBuckets []float64
	StepBuckets  []float64
	// this is a per Agv script. Add agv id to the configuration.
	AgvId agv.AgvId
}

// Register my plugin creator at init time. Creator is a method on the source based configuration
func init() {
	plugin.RegisterPlugin("agv001_run", cfg_agv001.Configure)
	plugin.RegisterPlugin("agv003_run", cfg_agv003.Configure)
	plugin.RegisterPlugin("agv004_run", cfg_agv004.Configure)
	plugin.RegisterPlugin("agv006_run", cfg_agv006.Configure)
}

