package charging

import (
	"context"
	"errors"
	"fmt"
	"slices"
	"time"

	"github.com/Kerrigan-Automation/overmind/public/lib/eidns"
	faccess "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go"
	agv_managerspec "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/conveyance/mobile/agv_manager"
	agvpb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/conveyance/mobile/agv"
	agv_managerpb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/conveyance/mobile/agv_manager"
	instancepb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/escript/instance"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/commands"
	"google.golang.org/protobuf/types/known/durationpb"

	agv "github.com/Kerrigan-Automation/overmind/public/lib/fm/agv"
	plugin "github.com/Kerrigan-Automation/overmind/public/lib/script/go_plugin"
	"go.uber.org/zap"
)

// update the active step status of the script.
func (s *script) updateActiveStepWithReason(reason string, status instancepb.StepStatus, deferNotification bool) {
	s.psp.UpdateState(func(state *instancepb.State, detailed *instancepb.VerboseState) (plugin.UpdateType, error) {

		// add tags from exported state of agv control? e.g. path. Let's see if we need it gives 'reason' may
		// contain enough. deferNotification tells us we do not need to indicate change because caller knows
		// we are going to issue an update anyway (e.g. closing step, closing cycle). We use deferNotification
		// to shortcircuit change comparison, and to force update in return.

		if len(detailed.ActiveSteps) > 0 {
			fs := detailed.ActiveSteps[0]
			if fs != nil {
				update := false
				if deferNotification || fs.Status != status || fs.Reason != reason {
					fs.Status = status
					fs.Reason = reason
					update = true
				}
				if s.waitingOnJob != "" && (deferNotification || !slices.Contains(fs.JobIds, s.waitingOnJob)) {
					fs.JobIds = []string{s.waitingOnJob}
					update = true
				}

				// we track entity ids but don't issue update just because of entityid changes. We may tighten this
				// in future to check for changes herre.
				fs.EntityIds = s.entityIds

				if update && !deferNotification {
					return plugin.UpdateTypeOnlyDetailed, nil
				}
			}
		}
		return plugin.UpdateTypeNone, nil
	})
}

// reconcileStage performs a one-time reconciliation at startup to populate timeout tracking
// for any existing charging commands.
func reconcileStage() *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "reconcile",
		Op: func(ctx context.Context, s *script) error {
			// Get all control states to find AGVs leased to us
			allControlStates := s.allAgvControlStates.AllStates()
			myScriptId := s.svc.MyScriptId()

			for agvId, controlState := range allControlStates {
				if !leaseBelongsToScript(controlState, myScriptId) {
					continue
				}

				// Check for active charging command
				if controlState.ActiveCommand != nil && isChargingCommand(controlState.ActiveCommand) {
					cmdInstance := controlState.ActiveCommand.CommandInstance
					if cmdInstance != nil && cmdInstance.GetState() == commands.CommandState_COMMAND_STATE_ACTIVE {
						// We found an active charging command. We don't know exactly when it started if we just restarted,
						// but we can default to "now" to give it a full timeout period.
						s.controlStateChargingCommandTimeout[agvId] = time.Now()

						// Also mark the waypoint as in use
						if wp := resolveChargingWaypoint(controlState); wp != "" {
							s.chargingWaypointsInUse[wp] = agvId
						}
					}
				}
			}
			return nil
		},
	}
}

// waitForEventsStage blocks until an event is received from any tracker
func waitForEventsStage() *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "waitForEvents",
		Op: func(ctx context.Context, s *script) error {
			s.logger.Debug("Waiting for events...")
			s.updateActiveStepWithReason("Waiting for events...", instancepb.StepStatus_STEP_STATUS_EXECUTING, false)

			// Check state immediately before waiting
			if nextStep, ok := s.evaluateState(ctx); ok {
				s.updateActiveStepWithReason(fmt.Sprintf("State evaluation triggered %s", nextStep), instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
				return plugin.NewErrRestartScriptStepByName(fmt.Errorf("state evaluation triggered %s", nextStep), nextStep, s.seq)
			}

			for {
				// Wait for event
				if err := s.waitForEvents(ctx); err != nil {
					return err
				}

				// Evaluate state
				if nextStep, ok := s.evaluateState(ctx); ok {
					s.updateActiveStepWithReason(fmt.Sprintf("State evaluation triggered %s", nextStep), instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
					return plugin.NewErrRestartScriptStepByName(fmt.Errorf("state evaluation triggered %s", nextStep), nextStep, s.seq)
				}

				// If no action needed, loop back and wait for next event
				s.updateActiveStepWithReason("Waiting for next event...", instancepb.StepStatus_STEP_STATUS_EXECUTING, false)
			}
		},
	}
}

// evaluateState analyzes the current state and decides the next action.
// Returns the name of the next step and true if an action is required.
func (s *script) evaluateState(ctx context.Context) (string, bool) {
	myScriptId := s.svc.MyScriptId()
	allControlStates := s.allAgvControlStates.AllStates()
	allAgvStates := s.allAgvStates.AllStates()

	// 1. Check leased AGVs for charge completion
	for agvId, controlState := range allControlStates {
		if !leaseBelongsToScript(controlState, myScriptId) {
			continue
		}

		// Check if we're tracking this as a charging job
		if _, ok := s.controlStateChargingCommandTimeout[agvId]; !ok {
			continue
		}

		agvState, _ := s.allAgvStates.State(agvId)
		if agvState == nil || agvState.State == nil {
			continue
		}

		// Check if the active charge command has completed
		// The device proxy clears ActiveCommand when charging finishes
		hasActiveChargeCommand := false
		if agvState.State.ActiveCommand != nil && agvState.State.ActiveCommand.GetChargeOpRequest() != nil {
			hasActiveChargeCommand = true
			// Mark that we've seen the command become active
			s.activeStateChargeCommandSeenInProxy[agvId] = true
		}

		isCharging := agvState.State.BatteryState != nil && agvState.State.BatteryState.GetCharging()

		// Only check for completion if we've previously seen the command active
		// This prevents false positives immediately after sending the command
		if s.activeStateChargeCommandSeenInProxy[agvId] && !hasActiveChargeCommand && !isCharging {
			s.logger.Info("Charge command completed, releasing lease",
				zap.String("agv_id", agvId.String()))
			return "releaseLease", true
		}

		// 1.5 Check for command timeout (AGV stuck en route to charger)
		// Only enforce timeout BEFORE we've seen the proxy charge command active
		if startTime, ok := s.controlStateChargingCommandTimeout[agvId]; ok {
			if !s.activeStateChargeCommandSeenInProxy[agvId] && time.Since(startTime) > s.cfg.CommandTimeout {
				s.logger.Warn("Command timeout - AGV stuck en route to charger, releasing lease",
					zap.String("agv_id", agvId.String()),
					zap.Duration("elapsed", time.Since(startTime)),
					zap.Duration("timeout", s.cfg.CommandTimeout))
				return "releaseLease", true
			}
		}
	}

	// 2. Check for new candidates to charge
	// Only if we have available charging stations
	availableWaypoints := s.getAvailableChargingWaypoints(ctx)
	if len(availableWaypoints) > 0 {
		_, found := s.findChargingCandidate(allAgvStates, allControlStates)
		if found {
			return "startCharge", true
		}
	}

	return "", false
}

// startChargeStage finds a candidate and starts charging
func startChargeStage() *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "startCharge",
		Op: func(ctx context.Context, s *script) error {
			s.updateActiveStepWithReason("Starting charge sequence...", instancepb.StepStatus_STEP_STATUS_EXECUTING, false)

			// Find candidate
			allControlStates := s.allAgvControlStates.AllStates()
			allAgvStates := s.allAgvStates.AllStates()

			availableWaypoints := s.getAvailableChargingWaypoints(ctx)
			if len(availableWaypoints) == 0 {
				s.updateActiveStepWithReason("No available charging waypoints", instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
				return plugin.NewErrRestartScriptStepByName(fmt.Errorf("no available waypoints"), "waitForEvents", s.seq)
			}

			candidateAgvId, found := s.findChargingCandidate(allAgvStates, allControlStates)
			if !found {
				s.updateActiveStepWithReason("No candidate found", instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
				return plugin.NewErrRestartScriptStepByName(fmt.Errorf("no candidate found"), "waitForEvents", s.seq)
			}

			s.updateActiveStepWithReason(fmt.Sprintf("Found candidate %s, acquiring lease...", candidateAgvId), instancepb.StepStatus_STEP_STATUS_EXECUTING, false)

			// Acquire Lease
			if err := s.acquireLeaseForCharging(ctx, candidateAgvId); err != nil {
				s.logger.Warn("Failed to acquire lease", zap.String("agv_id", candidateAgvId.String()), zap.Error(err))
				s.updateActiveStepWithReason(fmt.Sprintf("Failed to acquire lease for %s: %v", candidateAgvId, err), instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
				return plugin.NewErrRestartScriptStepByName(fmt.Errorf("failed to acquire lease"), "waitForEvents", s.seq)
			}

			// Send Start Command
			waypoint := availableWaypoints[0]
			s.updateActiveStepWithReason(fmt.Sprintf("Lease acquired for %s, sending to %s...", candidateAgvId, waypoint), instancepb.StepStatus_STEP_STATUS_EXECUTING, false)

			_, err := s.sendChargeCommand(ctx, candidateAgvId, waypoint)
			if err != nil {
				s.logger.Warn("Failed to start charge", zap.String("agv_id", candidateAgvId.String()), zap.Error(err))
				s.updateActiveStepWithReason(fmt.Sprintf("Failed to start charge for %s: %v", candidateAgvId, err), instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
				// Release lease if start failed
				releaseMyAgvLease(ctx, s, candidateAgvId)
				return plugin.NewErrRestartScriptStepByName(fmt.Errorf("failed to start charge"), "waitForEvents", s.seq)
			}

			// Track timeout
			s.controlStateChargingCommandTimeout[candidateAgvId] = time.Now()
			s.chargingWaypointsInUse[waypoint] = candidateAgvId

			s.updateActiveStepWithReason(fmt.Sprintf("Charge started for %s at %s", candidateAgvId, waypoint), instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
			return plugin.NewErrRestartScriptStepByName(fmt.Errorf("charge started"), "waitForEvents", s.seq)
		},
	}
}

// releaseLeaseStage releases the lease for an AGV that has completed charging
func releaseLeaseStage() *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "releaseLease",
		Op: func(ctx context.Context, s *script) error {
			s.updateActiveStepWithReason("Releasing lease for completed charge...", instancepb.StepStatus_STEP_STATUS_EXECUTING, false)

			myScriptId := s.svc.MyScriptId()
			allControlStates := s.allAgvControlStates.AllStates()

			// Find the AGV that completed charging
			for agvId, controlState := range allControlStates {
				if !leaseBelongsToScript(controlState, myScriptId) {
					continue
				}

				agvState, _ := s.allAgvStates.State(agvId)
				if agvState == nil || agvState.State == nil {
					continue
				}

				// Check if charging has completed
				hasActiveChargeCommand := false
				if agvState.State.ActiveCommand != nil && agvState.State.ActiveCommand.GetChargeOpRequest() != nil {
					hasActiveChargeCommand = true
				}

				isCharging := agvState.State.BatteryState != nil && agvState.State.BatteryState.GetCharging()

				if !hasActiveChargeCommand && !isCharging {
					s.updateActiveStepWithReason(fmt.Sprintf("Releasing lease for %s...", agvId), instancepb.StepStatus_STEP_STATUS_EXECUTING, false)

					// Release lease
					if err := releaseMyAgvLease(ctx, s, agvId); err != nil {
						s.logger.Warn("Failed to release lease", zap.String("agv_id", agvId.String()), zap.Error(err))
						s.updateActiveStepWithReason(fmt.Sprintf("Failed to release lease for %s: %v", agvId, err), instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
					} else {
						// Wait for the lease release to be reflected in the tracker
						s.updateActiveStepWithReason(fmt.Sprintf("Lease released for %s, waiting for confirmation...", agvId), instancepb.StepStatus_STEP_STATUS_EXECUTING, false)
						if err := s.waitForLeaseRelease(ctx, agvId); err != nil {
							s.logger.Warn("Timed out waiting for lease release update", zap.String("agv_id", agvId.String()), zap.Error(err))
						}
					}

					// Cleanup
					waypoint := resolveChargingWaypoint(controlState)
					if waypoint == "" {
						waypoint = controlState.GetCurrentWaypointId()
					}
					delete(s.controlStateChargingCommandTimeout, agvId)
					delete(s.activeStateChargeCommandSeenInProxy, agvId)
					if waypoint != "" {
						delete(s.chargingWaypointsInUse, waypoint)
					}

					s.logger.Info("Charging completed and lease released",
						zap.String("agv_id", agvId.String()),
						zap.String("waypoint", waypoint))

					// Process one at a time
					s.updateActiveStepWithReason(fmt.Sprintf("Lease released for %s", agvId), instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
					return plugin.NewErrRestartScriptStepByName(fmt.Errorf("lease released"), "waitForEvents", s.seq)
				}
			}

			// Should not reach here if evaluateState is working correctly
			s.updateActiveStepWithReason("No lease to release found", instancepb.StepStatus_STEP_STATUS_COMPLETED_SUCCESS, true)
			return plugin.NewErrRestartScriptStepByName(fmt.Errorf("no lease to release"), "waitForEvents", s.seq)
		},
	}
}

// waitForLeaseRelease blocks until the lease for the given AGV is no longer held by this script,
// or the context times out.
func (s *script) waitForLeaseRelease(ctx context.Context, agvId agv.AgvId) error {
	ctx, cancel := context.WithTimeout(ctx, s.cfg.LeaseReleaseWaitTimeout)
	defer cancel()

	ticker := time.NewTicker(s.cfg.LeaseReleasePollingInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-ticker.C:
			controlState, _ := s.allAgvControlStates.State(agvId)
			if !leaseBelongsToScript(controlState, s.svc.MyScriptId()) {
				return nil
			}
		case <-s.allAgvControlStates.NotificationChan():
			controlState, _ := s.allAgvControlStates.State(agvId)
			if !leaseBelongsToScript(controlState, s.svc.MyScriptId()) {
				return nil
			}
		}
	}
}

// getAvailableChargingWaypoints fetches charging stations from track config and filters out those already in use.
func (s *script) getAvailableChargingWaypoints(ctx context.Context) []string {
	chargingWaypoints, err := s.trackConfig.ChargingStationNodeIds(ctx, s.svc.FabricClient(), s.eidNs)
	if err != nil {
		s.logger.Warn("Failed to get charging station waypoints", zap.Error(err))
		return nil
	}

	available := make([]string, 0)
	for _, wp := range chargingWaypoints {
		if _, inUse := s.chargingWaypointsInUse[wp]; !inUse {
			available = append(available, wp)
		}
	}
	return available
}

// findChargingCandidate searches all tracked AGVs and returns the one with the lowest battery
// that needs charging. Returns the AGV ID and true if found, or AgvIdUnknown and false if none eligible.
func (s *script) findChargingCandidate(allStates map[agv.AgvId]*agvpb.ActiveState, allControlStates map[agv.AgvId]*agv_managerpb.AgvControlState) (agv.AgvId, bool) {
	if len(allStates) == 0 {
		return agv.AgvIdUnknown, false
	}

	var bestCandidate agv.AgvId
	var lowestBattery float32 = 100.0 // Start above threshold so we only consider eligible AGVs
	found := false

	for agvId, agvState := range allStates {
		controlState := allControlStates[agvId]
		if !s.isEligibleForCharging(agvId, agvState, controlState) {
			continue
		}

		// Extract battery percentage (we know it's valid from isEligibleForCharging)
		batteryPercent := agvState.State.BatteryState.GetPercent()

		// Track the AGV with the lowest battery
		if batteryPercent < lowestBattery {
			lowestBattery = batteryPercent
			bestCandidate = agvId
			found = true
		}
	}

	if !found {
		return agv.AgvIdUnknown, false
	}

	return bestCandidate, true
}

// isEligibleForCharging checks if an AGV is a valid candidate for charging.
func (s *script) isEligibleForCharging(agvId agv.AgvId, agvState *agvpb.ActiveState, controlState *agv_managerpb.AgvControlState) bool {
	// Skip if already has a charging job (timeout tracked)
	if _, hasJob := s.controlStateChargingCommandTimeout[agvId]; hasJob {
		return false
	}

	// Skip if leased to someone else
	if controlState != nil && controlState.GetLease() != nil && controlState.GetLease().GetTo() != "" {
		return false
	}

	if agvState == nil || agvState.State == nil || agvState.State.BatteryState == nil {
		return false
	}

	// Skip if already charging
	if agvState.State.BatteryState.GetCharging() {
		return false
	}

	// Check battery threshold
	if agvState.State.BatteryState.GetPercent() >= s.cfg.LowBatteryThreshold {
		return false
	}

	return true
}

// acquireLeaseForCharging attempts to acquire a lease for the specified AGV.
func (s *script) acquireLeaseForCharging(ctx context.Context, agvId agv.AgvId) error {
	client := s.svc.FabricClient()
	targetId := eidns.NewAgvManagerEid(s.eidNs)
	leasedTo := s.svc.MyScriptId()

	req := &agv_managerpb.LeaseAgvRequest{
		LeasedTo:       leasedTo,
		CommandRequest: faccess.NewCommandRequest(),
		MandatedAgvIds: []string{agvId.String()},
	}

	ctxWithTimeout, cancel := context.WithTimeout(ctx, s.cfg.FabricRequestTimeout)
	defer cancel()

	result, err := agv_managerspec.GetLeaseOnAgvRequest(
		ctxWithTimeout,
		client,
		req,
		faccess.RequestWithTarget(targetId))
	if err != nil {
		return fmt.Errorf("lease request failed: %w", err)
	}

	response, err := result.Await(ctxWithTimeout)
	if err != nil {
		return fmt.Errorf("lease await failed: %w", err)
	}

	r := response.Response
	cr := r.GetCommandResponse()
	if cr.GetOutcome() != commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_ACCEPTED {
		return fmt.Errorf("lease rejected: %s", cr.GetDescription())
	}

	if r.GetAgvId() == "" {
		return fmt.Errorf("empty AGV ID in lease response")
	}

	return nil
}

// sendChargeCommand sends the CHARGE command to move to the charging waypoint and charge until conditions are met.
func (s *script) sendChargeCommand(ctx context.Context, agvId agv.AgvId, waypoint string) (string, error) {
	client := s.svc.FabricClient()
	targetId := eidns.NewAgvEid(s.eidNs, agvId.String())
	cr := faccess.NewCommandRequest()

	ctxWithTimeout, cancel := context.WithTimeout(ctx, s.cfg.FabricRequestTimeout)
	defer cancel()

	// Calculate charge duration if needed (0 means ignored by driver)
	var chargeDuration *durationpb.Duration
	if s.cfg.CommandTimeout > 0 {
		chargeDuration = durationpb.New(s.cfg.CommandTimeout)
	}

	reqResult, err := agv_managerspec.OperateLeasedAgvRequest(
		ctxWithTimeout,
		client,
		&agv_managerpb.OperateAgvRequest{
			CommandRequest: cr,
			Requestor:      s.svc.MyScriptId(),
			Command: &agv_managerpb.AgvCommand{
				WaypointId: waypoint,
				ChargeOpRequest: &agvpb.ChargeOpRequest{
					CommandRequest:       faccess.NewCommandRequest(),
					ChargeDuration:       chargeDuration,
					TargetBatteryPercent: s.cfg.StopChargeThreshold,
					PortId:               agv.PortIdDefault.String(),
				},
			},
		},
		faccess.RequestWithTarget(targetId),
	)
	if err != nil {
		return "", fmt.Errorf("operate request failed: %w", err)
	}

	resp, err := reqResult.Await(ctxWithTimeout)
	if err != nil {
		return "", fmt.Errorf("response await failed: %w", err)
	}

	cmdResp := resp.Response.GetCommandResponse()
	if cmdResp.GetOutcome() != commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_ACCEPTED {
		return "", fmt.Errorf("charge command rejected (%s)", cmdResp.GetOutcome().String())
	}

	s.logger.Info("Charge command accepted",
		zap.String("agv_id", agvId.String()),
		zap.String("command_id", cmdResp.GetId()),
		zap.String("waypoint", waypoint),
		zap.Float32("target_percent", s.cfg.StopChargeThreshold))

	return cmdResp.GetId(), nil
}

// releaseMyAgvLease releases the lease for the specified AGV.
func releaseMyAgvLease(ctx context.Context, s *script, agvId agv.AgvId) error {
	client := s.svc.FabricClient()
	targetId := eidns.NewAgvManagerEid(s.eidNs)
	leasedTo := s.svc.MyScriptId()

	request := &agv_managerpb.ReturnLeaseAgvRequest{
		CommandRequest: faccess.NewCommandRequest(),
		AgvId:          agvId.String(),
		LeasedTo:       leasedTo,
	}

	ctxWithTimeout, cancel := context.WithTimeout(ctx, s.cfg.FabricRequestTimeout)
	defer cancel()

	result, err := agv_managerspec.ReturnLeaseOnAgvRequest(ctxWithTimeout, client, request, faccess.RequestWithTarget(targetId))
	if err != nil {
		return err
	}

	response, err := result.Await(ctxWithTimeout)
	if err != nil {
		return err
	}

	r := response.Response.GetCommandResponse()
	if r.GetOutcome() != commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_ACCEPTED {
		return fmt.Errorf("failed to release lease for %s: %s", agvId.String(), r.GetOutcome().String())
	}

	return nil
}

// leaseBelongsToScript checks if the lease belongs to the script
func leaseBelongsToScript(controlState *agv_managerpb.AgvControlState, scriptID string) bool {
	return controlState != nil &&
		controlState.GetLease() != nil &&
		controlState.GetLease().GetTo() == scriptID
}

// resolveChargingWaypoint resolves the charging waypoint from the control state
func resolveChargingWaypoint(controlState *agv_managerpb.AgvControlState) string {
	if controlState == nil {
		return ""
	}

	// Primary: Extract waypoint directly from active command content (most reliable)
	if controlState.ActiveCommand != nil {
		if cmdContent := controlState.ActiveCommand.CommandContent; cmdContent != nil {
			if waypoint := cmdContent.GetWaypointId(); waypoint != "" {
				return waypoint
			}
		}
	}

	// Fallback: Use current waypoint ID from control state (represents AGV's current location)
	if waypointID := controlState.GetCurrentWaypointId(); waypointID != "" {
		return waypointID
	}
	return ""
}

// isChargingCommand checks if the active command is a charging command
func isChargingCommand(activeCmd *agv_managerpb.CommandRecord) bool {
	if activeCmd == nil || activeCmd.CommandContent == nil {
		return false
	}
	return activeCmd.CommandContent.GetChargeOpRequest() != nil
}

// cleanupAllLeases releases all leases held by this script.
// Called when the script is stopped to ensure we don't leave orphaned leases.
// Only releases leases if the cycle is actually being aborted (stopped/paused/error), not on step restarts.
func (s *script) cleanupAllLeases(ctx context.Context, err error) {
	// Only cleanup on actual cycle abort (stop, pause, error, etc.), not on step restarts
	// The sequencer wraps ErrScriptCycleAborted when the cycle is being aborted,
	// or the error itself is ErrScriptStopped/ErrScriptPaused
	isCycleAbort := errors.Is(err, plugin.ErrScriptCycleAborted) ||
		errors.Is(err, plugin.ErrScriptStopped) ||
		errors.Is(err, plugin.ErrScriptPaused)

	if !isCycleAbort {
		return
	}

	for agvId := range s.controlStateChargingCommandTimeout {
		s.logger.Info("Releasing lease on shutdown",
			zap.String("agv_id", agvId.String()),
			zap.Error(err))
		if releaseErr := releaseMyAgvLease(ctx, s, agvId); releaseErr != nil {
			s.logger.Warn("Failed to release lease on shutdown",
				zap.String("agv_id", agvId.String()),
				zap.Error(releaseErr))
		}
	}
	// Clear tracking maps
	s.controlStateChargingCommandTimeout = make(map[agv.AgvId]time.Time)
	s.activeStateChargeCommandSeenInProxy = make(map[agv.AgvId]bool)
	s.chargingWaypointsInUse = make(map[string]agv.AgvId)
}

