package charging

import (
	"context"
	"fmt"
	"sync"
	"time"

	agv "github.com/Kerrigan-Automation/overmind/public/lib/fm/agv"
	plugin "github.com/Kerrigan-Automation/overmind/public/lib/script/go_plugin"
	"github.com/Kerrigan-Automation/overmind/public/lib/eidns"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/escript/instance"
	configpb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/config"
	"github.com/cenkalti/backoff/v5"
	"go.uber.org/zap"
	"google.golang.org/protobuf/types/known/timestamppb"
)

func (cfg *Config) Configure(ctx context.Context, wg *sync.WaitGroup, svc plugin.HostServices) (plugin.ScriptPlugin, error) {
	defer wg.Done()

	// Validate and normalize thresholds
	if cfg.LowBatteryThreshold < 0 || cfg.LowBatteryThreshold > 100 {
		return nil, fmt.Errorf("LowBatteryThreshold must be between 0 and 100, got %f", cfg.LowBatteryThreshold)
	}

	// Normalize StopChargeThreshold: calculate default if not set, ensure it's valid
	if cfg.StopChargeThreshold <= 0 {
		cfg.StopChargeThreshold = cfg.LowBatteryThreshold + 10.0
	}
	if cfg.StopChargeThreshold < cfg.LowBatteryThreshold {
		cfg.StopChargeThreshold = cfg.LowBatteryThreshold
	}
	if cfg.StopChargeThreshold > 100.0 {
		cfg.StopChargeThreshold = 100.0
	}

	// Sanitize CommandTimeout: set default if zero or negative, enforce reasonable bounds
	if cfg.CommandTimeout <= 0 {
		cfg.CommandTimeout = 60 * time.Second // Default timeout: 60 seconds
	}

	// Sanitize FabricRequestTimeout: set default if zero or negative
	if cfg.FabricRequestTimeout <= 0 {
		cfg.FabricRequestTimeout = 5 * time.Second
	}

	// Sanitize LeaseReleaseWaitTimeout: set default if zero or negative
	if cfg.LeaseReleaseWaitTimeout <= 0 {
		cfg.LeaseReleaseWaitTimeout = 5 * time.Second
	}

	// Sanitize LeaseReleasePollingInterval: set default if zero or negative
	if cfg.LeaseReleasePollingInterval <= 0 {
		cfg.LeaseReleasePollingInterval = 100 * time.Millisecond
	}

	// Start up stopped. The safest possible way. This may have to change to reflect previous activated state.
	initDesired := &instance.ControlRequest{
		RequestedMode: instance.Mode_MODE_STOPPED,
	}
	initState := &instance.State{
		// NOTE that we do inject Name, BootedAt directly. These are injected by the host since the host know these
		// if we do not set them. (If we did set them they would not be overwritten)
		ActiveMode:     instance.Mode_MODE_STOPPED,
		RequestedMode:  instance.Mode_MODE_STOPPED,
		RequestedOn:    timestamppb.Now(),
		TransitionedOn: timestamppb.Now(),
	}

	// pullScriptPlugin allows script to manage tags and detailed tags on reported state if necessary.
	// It is also handed to sequencer to allow sequencer to honour control requests from overming.
	psp := plugin.NewPullScriptPlugin(initState, initDesired, svc, cfg.CycleBuckets, cfg.StepBuckets)

	// publish a short description tag for operators
	psp.UpdateState(func(state *instance.State, verbose *instance.VerboseState) (plugin.UpdateType, error) {
		desc := cfg.Description
		if desc == "" {
			desc = "simple sequencer loop"
		}
		t := state.Tags
		if t == nil {
			t = &configpb.TagSet{}
		}
		t.Tags = append(t.Tags, &configpb.Tag{Key: "description", Value: desc})
		state.Tags = t
		return plugin.UpdateTypeIncludesCore, nil
	})
	// set up script with the ability to map to global namespace for identities.
	eidNs := svc.EidNs()

	script := &script{
		ctx:                                 ctx,
		cfg:                                 cfg,
		svc:                                 svc,
		psp:                                 psp,
		eidNs:                               eidNs,
		controlStateChargingCommandTimeout:  make(map[agv.AgvId]time.Time),
		activeStateChargeCommandSeenInProxy: make(map[agv.AgvId]bool),
		chargingWaypointsInUse:              make(map[string]agv.AgvId),
		logger:                              svc.Logger(),
	}

	// We are going to watch all AGV active state updates (battery, position, etc.) so we can
	// monitor battery levels for all AGVs and send them to charging when needed.
	wg.Add(1)
	var err error
	script.allAgvStates, err = NewTrackAllAgvStatesWrapper(ctx, wg, svc.FabricClient(), eidNs, cfg.Backoff, svc.Logger())
	if err != nil {
		return nil, err
	}

	// We are going to watch all AGV control state updates (lease, commands, etc.) so we can
	// always know lease ownership for all AGVs.
	wg.Add(1)
	script.allAgvControlStates, err = NewTrackAllAgvControlStatesWrapper(ctx, wg, svc.FabricClient(), eidNs, cfg.Backoff, svc.Logger())
	if err != nil {
		return nil, err
	}

	// We are going to watch the track configuration updates. We want to track the active track
	// configuration so we can use it in our script logic.
	wg.Add(1)
	script.trackConfig, err = NewTrackTrackConfigWrapper(ctx, wg, svc.FabricClient(), cfg.Backoff, svc.Logger())
	if err != nil {
		return nil, err
	}

	sequencer, err := plugin.NewSequencer(cfg.SequenceConfig, psp, svc)
	if err != nil {
		return nil, err
	}
	script.seq = sequencer

	wg.Add(1)
	go sequencer.Runner(ctx, wg, script)

	return psp, nil
}

// script tracks context made available to every callback in steps.
type script struct {
	ctx   context.Context
	cfg   *Config
	svc   plugin.HostServices
	psp   *plugin.PullScriptPlugin
	eidNs *eidns.EidNsManager
	seq   *plugin.Sequencer[*script]
	// controlStateChargingCommandTimeout tracks the start time of active charging jobs for timeout enforcement.
	// We only track this for AGVs we are actively managing and are being routed to the charging waypoint
	// (leased + control charging command sent). This timeout only applies to the control command and is
	// discarded when the proxy receives the active state charge command.
	controlStateChargingCommandTimeout map[agv.AgvId]time.Time
	// activeStateChargeCommandSeenInProxy tracks whether we've seen the charge command become active in AGV proxy state.
	// This prevents false positives when checking for completion while agv is being routed to the charging \
	// waypoint / immediately before starting charge.
	activeStateChargeCommandSeenInProxy map[agv.AgvId]bool
	// All AGV active states - tracks battery level, position, etc. from all AGV devices
	allAgvStates *TrackedAgvStatesWrapper
	// All AGV control states - tracks lease, commands, etc. from all AGV controllers
	allAgvControlStates *TrackedAllAgvControlStatesWrapper
	// Track configuration state - tracks the active track configuration
	trackConfig *TrackedTrackConfigWrapper
	// Track which charging waypoints are in use (waypoint -> AGV ID)
	chargingWaypointsInUse map[string]agv.AgvId
	logger                 *zap.Logger

	// Reporting state
	waitingOnJob string
	entityIds    []*configpb.EntityKindAndName
}

type Config struct {
	// Short description published as a tag for operators
	Description string
	// K/V which are meaningful to me, the script writer. I get to see this in UI. And when
	// at the ui, I collect details state from script I will also see the detailed KV.
	Tags         configpb.TagSet
	DetailedTags configpb.TagSet
	// sequencer configuration - we put all the sequence steps we want to implement in here.
	SequenceConfig plugin.SequencerConfig[*script]
	// metrics buckets used to determine histogram buckets for duration metrics of cycles and steps.
	Backoff      *backoff.ExponentialBackOff
	CycleBuckets []float64
	StepBuckets  []float64
	// LowBatteryThreshold is the battery percentage below which an AGV should be sent to charge
	LowBatteryThreshold float32
	// StopChargeThreshold is passed to the agv through the charge command as the threshold to stop charging.
	StopChargeThreshold float32
	// ChargeDuration is passed to the agv through the charge command as the duration to charge for, relevant for
	// agvs with lead-acid batteries.
	ChargeDuration time.Duration
	// CommandTimeout is the maximum time to wait for a control command (operate request to mover) to complete.
	// If the control command is still ACTIVE after this timeout, we send STOP before releasing lease.
	// If zero, defaults to 60 seconds.
	CommandTimeout time.Duration
	// FabricRequestTimeout is the timeout for Fabric API calls (lease acquire, operate, release).
	// If zero, defaults to 5 seconds.
	FabricRequestTimeout time.Duration
	// LeaseReleaseWaitTimeout is the timeout waiting for lease release confirmation from tracker updates.
	// If zero, defaults to 5 seconds.
	LeaseReleaseWaitTimeout time.Duration
	// LeaseReleasePollingInterval is the polling interval when waiting for lease release confirmation.
	// If zero, defaults to 100 milliseconds.
	LeaseReleasePollingInterval time.Duration
}

// Register my plugin creator at init time. Creator is a method on the source based configuration
func init() {
	plugin.RegisterPlugin("charging", cfg_charging.Configure)
}

// waitForEvents blocks until an event is received from any of the trackers or the context is cancelled.
func (s *script) waitForEvents(ctx context.Context) error {
	select {
	case <-s.allAgvStates.NotificationChan():
		return nil
	case <-s.allAgvControlStates.NotificationChan():
		return nil
	case <-s.trackConfig.NotificationChan():
		return nil
	case <-ctx.Done():
		return ctx.Err()
	}
}

