)

/////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
//
// Wrapper implementations using generated SDK trackers
//
//

// TrackedAgvStatesWrapper wraps multiple agv.TrackedActiveState instances to track all AGVs
type TrackedAgvStatesWrapper struct {
	notification chan struct{}
	stateMu      sync.RWMutex
	states       map[agv.AgvId]*agvpb.ActiveState // Map of AGV ID to their active state
	lastUpdate   time.Time
	logger       *zap.Logger
	eidNs        *eidns.EidNsManager
}

// State returns the active state for a specific AGV, or nil if not available
func (t *TrackedAgvStatesWrapper) State(agvId agv.AgvId) (*agvpb.ActiveState, time.Time) {
	t.stateMu.RLock()
	defer t.stateMu.RUnlock()
	state, ok := t.states[agvId]
	if !ok {
		return nil, t.lastUpdate
	}
	return state, t.lastUpdate
}

// AllStates returns a map of all tracked AGV states
func (t *TrackedAgvStatesWrapper) AllStates() map[agv.AgvId]*agvpb.ActiveState {
	t.stateMu.RLock()
	defer t.stateMu.RUnlock()
	result := make(map[agv.AgvId]*agvpb.ActiveState)
	for k, v := range t.states {
		result[k] = v
	}
	return result
}

// NotificationChan returns a channel which is updated whenever an update to any AGV active state is received
func (t *TrackedAgvStatesWrapper) NotificationChan() <-chan struct{} {
	return t.notification
}

// WaitForUpdate blocks waiting on update from any AGV
func (t *TrackedAgvStatesWrapper) WaitForUpdate(ctx context.Context) {
	select {
	case <-t.notification:
	case <-ctx.Done():
	}
}

// NewTrackAllAgvStatesWrapper creates a wrapper that subscribes to all AGV active states using EntityIdAny
func NewTrackAllAgvStatesWrapper(
	ctx context.Context,
	wg *sync.WaitGroup,
	fabric *faccess.Client,
	eidNs *eidns.EidNsManager,
	bo *backoff.ExponentialBackOff,
	logger *zap.Logger) (*TrackedAgvStatesWrapper, error) {
	defer wg.Done()

	if bo == nil {
		bo = backoff.NewExponentialBackOff()
	}

	if logger == nil {
		logger = zap.NewNop()
	}

	if fabric == nil {
		return nil, errors.New("fabric client must be provided")
	}

	if eidNs == nil {
		return nil, errors.New("eidNs must be provided")
	}

	opts := []faccess.SubscribeOpt{
		faccess.SubscribeWithImplicitAck(),
		faccess.SubscribeWithTarget(core.EntityIdAny)} // Subscribe to all AGVs

	t := &TrackedAgvStatesWrapper{
		notification: make(chan struct{}, 1),
		stateMu:      sync.RWMutex{},
		states:       make(map[agv.AgvId]*agvpb.ActiveState),
		logger:       logger.Named("track_all_agv_states"),
		eidNs:        eidNs,
	}

	wg.Add(1)
	go func() {
		var agvStateSubscription *agvspec.ActiveStateSubscribeResult

		defer func() {
			if agvStateSubscription != nil {
				shutdownContext, cancel := context.WithTimeout(context.Background(), time.Second)
				agvStateSubscription.CancelSubscription(shutdownContext)
				cancel()
			}
			t.logger.Info("exiting")
			wg.Done()
		}()

		agvStateSubscription, err := backoff.Retry(
			ctx,
			faccess.ForSubscriptionRetry(
				agvspec.ActiveStateSubscribe,
				ctx,
				fabric,
				opts...,
			),
			backoff.WithBackOff(bo),
			backoff.WithMaxTries(uint(0)),
			backoff.WithMaxElapsedTime(0),
		)
		if err != nil {
			return
		}

		t.waitForAgvStateUpdates(ctx, agvStateSubscription, bo)
	}()

	return t, nil
}

func (t *TrackedAgvStatesWrapper) waitForAgvStateUpdates(
	ctx context.Context,
	subscription *agvspec.ActiveStateSubscribeResult,
	bo *backoff.ExponentialBackOff) {
	defer func() {
		t.logger.Info("exiting")
	}()

	for ctx.Err() == nil {
		next, err := backoff.Retry(ctx, func() (*agvspec.ActiveStateProperty, error) {
			return subscription.AwaitNext(ctx)
		},
			backoff.WithBackOff(bo),
			backoff.WithMaxTries(uint(0)),
			backoff.WithMaxElapsedTime(0),
		)

		if err != nil {
			continue
		}

		// Extract AGV ID from entity ID
		entityId, err := next.Target()
		if err != nil {
			t.logger.Error("failed to get target from agv active state update", zap.Error(err))
			continue
		}

		// Extract AGV ID from entity ID (format: om_agv_XXX)
		agvIdStr, ok := eidns.ParseAgvEid(t.eidNs, entityId)
		if !ok || agvIdStr == "" {
			t.logger.Debug("failed to extract agv id from entity id",
				zap.String("entity_id", entityId.String()))
			continue
		}

		agvId := agv.AgvId(agvIdStr)
		t.handleAgvStateUpdate(agvId, next.Origin(), next.Property)
	}
}

// handleAgvStateUpdate updates the local state of an AGV
func (t *TrackedAgvStatesWrapper) handleAgvStateUpdate(agvId agv.AgvId, originated time.Time, state *agvpb.ActiveState) {
	t.stateMu.Lock()
	t.states[agvId] = state
	t.lastUpdate = originated
	t.stateMu.Unlock()

	select {
	case t.notification <- struct{}{}:
	default:
		// pending update
	}
}

// TrackedAllAgvControlStatesWrapper wraps subscription to all AGV control states
type TrackedAllAgvControlStatesWrapper struct {
