// NewTrackAllAgvControlStatesWrapper creates a wrapper that subscribes to all AGV control states using EntityIdAny
func NewTrackAllAgvControlStatesWrapper(
	ctx context.Context,
	wg *sync.WaitGroup,
	fabric *faccess.Client,
	eidNs *eidns.EidNsManager,
	bo *backoff.ExponentialBackOff,
	logger *zap.Logger) (*TrackedAllAgvControlStatesWrapper, error) {
	defer wg.Done()

	if bo == nil {
		bo = backoff.NewExponentialBackOff()
	}

	if logger == nil {
