	}

	if eidNs == nil {
		return nil, errors.New("eidNs must be provided")
	}

	opts := []faccess.SubscribeOpt{
		faccess.SubscribeWithImplicitAck(),
		faccess.SubscribeWithTarget(core.EntityIdAny)} // Subscribe to all AGVs

	t := &TrackedAllAgvControlStatesWrapper{
		notification: make(chan struct{}, 1),
		stateMu:      sync.RWMutex{},
		states:       make(map[agv.AgvId]*agv_managerpb.AgvControlState),
		logger:       logger.Named("track_all_agv_control_states"),
		eidNs:        eidNs,
	}

	wg.Add(1)
	go func() {
		var agvControlStateSubscription *agv_managerspec.AgvControlStateSubscribeResult

		defer func() {
			if agvControlStateSubscription != nil {
				shutdownContext, cancel := context.WithTimeout(context.Background(), time.Second)
				agvControlStateSubscription.CancelSubscription(shutdownContext)
				cancel()
			}
			t.logger.Info("exiting")
			wg.Done()
		}()

		agvControlStateSubscription, err := backoff.Retry(
			ctx,
			faccess.ForSubscriptionRetry(
				agv_managerspec.AgvControlStateSubscribe,
				ctx,
				fabric,
				opts...,
			),
			backoff.WithBackOff(bo),
			backoff.WithMaxTries(uint(0)),
			backoff.WithMaxElapsedTime(0),
		)
		if err != nil {
			return
		}

		t.waitForAgvControlStateUpdates(ctx, agvControlStateSubscription, bo)
	}()

	return t, nil
}

func (t *TrackedAllAgvControlStatesWrapper) waitForAgvControlStateUpdates(
	ctx context.Context,
	subscription *agv_managerspec.AgvControlStateSubscribeResult,
	bo *backoff.ExponentialBackOff) {
	defer func() {
		t.logger.Info("exiting")
	}()

	for ctx.Err() == nil {
		next, err := backoff.Retry(ctx, func() (*agv_managerspec.AgvControlStateProperty, error) {
			return subscription.AwaitNext(ctx)
		},
			backoff.WithBackOff(bo),
			backoff.WithMaxTries(uint(0)),
			backoff.WithMaxElapsedTime(0),
		)

		if err != nil {
			continue
		}

		// Extract AGV ID from entity ID
		entityId, err := next.Target()
		if err != nil {
			t.logger.Error("failed to get target from agv control state update", zap.Error(err))
			continue
		}

		// Extract AGV ID from entity ID (format: om_agv_XXX)
		agvIdStr, ok := eidns.ParseAgvEid(t.eidNs, entityId)
		if !ok || agvIdStr == "" {
			t.logger.Debug("failed to extract agv id from entity id",
				zap.String("entity_id", entityId.String()))
			continue
		}

		agvId := agv.AgvId(agvIdStr)
		t.handleAgvControlStateUpdate(agvId, next.Origin(), next.Property)
	}
}

// handleAgvControlStateUpdate updates the local state of an AGV control state
func (t *TrackedAllAgvControlStatesWrapper) handleAgvControlStateUpdate(agvId agv.AgvId, originated time.Time, state *agv_managerpb.AgvControlState) {
	t.stateMu.Lock()
	t.states[agvId] = state
	t.lastUpdate = originated
	t.stateMu.Unlock()

	select {
	case t.notification <- struct{}{}:
	default:
		// pending update
	}
}

// TrackedTrackConfigWrapper wraps trackspec.TrackedState and adds charging station helper methods
type TrackedTrackConfigWrapper struct {
	impl                     *trackspec.TrackedState
	stateMu                  sync.RWMutex
	cachedChargingStationIds []string // Cached list of charging station node IDs
	logger                   *zap.Logger
}

// State return the immutable last TrackManagerState received if any, and the
// timestamp of origin of the update.
func (t *TrackedTrackConfigWrapper) State() (*trackpb.TrackManagerState, time.Time) {
	return t.impl.State()
}

// NotificationChan returns a channel which is updated whenever an update to TrackManagerState is
// received, if there is no notification already pending.
func (t *TrackedTrackConfigWrapper) NotificationChan() <-chan struct{} {
	return t.impl.NotificationChan()
}

// WaitForUpdate blocks waiting on update, and returns new updated state on return, along with
// time of origin.
func (t *TrackedTrackConfigWrapper) WaitForUpdate(ctx context.Context) (*trackpb.TrackManagerState, time.Time) {
	return t.impl.WaitForUpdate(ctx)
}

// NewTrackTrackConfigWrapper creates a wrapper around trackspec.TrackedState with charging station helpers
func NewTrackTrackConfigWrapper(
	ctx context.Context,
	wg *sync.WaitGroup,
	fabric *faccess.Client,
	bo *backoff.ExponentialBackOff,
	logger *zap.Logger) (*TrackedTrackConfigWrapper, error) {
	defer wg.Done()

	if logger == nil {
		logger = zap.NewNop()
	}

	// Use EntityIdAny for track manager state
	trackManagerEid := core.EntityIdAny
	trackedState, err := trackspec.NewTrackState(ctx, wg, fabric, trackManagerEid, bo)
	if err != nil {
		return nil, err
	}

	return &TrackedTrackConfigWrapper{
		impl:                     trackedState,
		cachedChargingStationIds: nil,
		logger:                   logger.Named("track_track_config"),
	}, nil
}

// ChargingStationNodeIds returns a list of node IDs that are charging stations from the active track configuration.
// This caches the result and refreshes it when the track configuration changes.
// Returns an empty slice if no track config is available or no charging stations are found.
func (t *TrackedTrackConfigWrapper) ChargingStationNodeIds(ctx context.Context, fabric *faccess.Client, eidNs *eidns.EidNsManager) ([]string, error) {
	state, _ := t.impl.State()
	trackId := ""
	if state != nil {
		trackId = state.GetActiveTrackId()
	}

	t.stateMu.RLock()
	cached := t.cachedChargingStationIds
	t.stateMu.RUnlock()

	// Return cached if available and track ID hasn't changed
	if cached != nil && state != nil {
		// Double-check track ID hasn't changed
		t.stateMu.RLock()
		currentState, _ := t.impl.State()
		if currentState != nil && currentState.GetActiveTrackId() == trackId {
			t.stateMu.RUnlock()
			return cached, nil
		}
		t.stateMu.RUnlock()
	}

	if trackId == "" {
		return nil, nil
	}

	// Fetch full track config via Fabric
	trackManagerEid := eidns.NewTrackManagerEid(eidNs)
	req := &trackpb.TrackConfigVersionRequest{
		CommandRequest: faccess.NewCommandRequest(),
		TrackId:        trackId,
	}

	result, err := trackspec.GetTrackConfigVersionRequest(ctx, fabric, req, faccess.RequestWithTarget(trackManagerEid))
	if err != nil {
		return nil, fmt.Errorf("failed to request track config version: %w", err)
	}
	resp, err := result.Await(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to await track config version: %w", err)
	}
	if resp.Response == nil || resp.Response.CommandResponse == nil {
		return nil, fmt.Errorf("empty track config response")
	}
	if resp.Response.CommandResponse.GetOutcome() == commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_FAILURE {
		return nil, fmt.Errorf("track config request failed: %s", resp.Response.CommandResponse.GetDescription())
	}

	var chargingStationIds []string
	for _, node := range resp.Response.Config.GetNodes() {
		if node.GetNodeType() == trackpb.NodeType_NODE_TYPE_CHARGING_STATION {
			chargingStationIds = append(chargingStationIds, node.GetNodeId())
		}
	}

	// Cache the result
	t.stateMu.Lock()
	// Double-check the track ID hasn't changed while we were querying
	currentState, _ := t.impl.State()
	if currentState != nil && currentState.GetActiveTrackId() == trackId {
		t.cachedChargingStationIds = chargingStationIds
		t.logger.Info("cached charging station node IDs",
			zap.Strings("charging_station_ids", chargingStationIds),
			zap.String("track_id", trackId))
	}
	t.stateMu.Unlock()

	return chargingStationIds, nil
}

// GetChargingStationNodeId returns a single charging station node ID from the active track.
// Returns empty string if none available or on error.
func (t *TrackedTrackConfigWrapper) GetChargingStationNodeId(ctx context.Context, fabric *faccess.Client, eidNs *eidns.EidNsManager) string {
	ids, err := t.ChargingStationNodeIds(ctx, fabric, eidNs)
	if err != nil {
		t.logger.Warn("failed to get charging station node IDs", zap.Error(err))
		return ""
	}
	if len(ids) > 0 {
		return ids[0]
	}
	return ""
}

