type Config struct {
	AgvName           string
	LoopStartWaypoint string
	LoopEndWaypoint   string
}

type script struct {
	cfg                    *Config
	svc                    plugin.HostServices
	psp                    *plugin.PullScriptPlugin
	eidNs                  *eidns.EidNsManager
	leasedTo               string
	seq                    *plugin.Sequencer[*script]
	logger                 *zap.Logger
	agvControlStateTracker *agvmgrsdk.TrackedAgvControlState
	// for diagnostics only...
	waitingOnJob string
}

func (cfg *Config) Configure(ctx context.Context, wg *sync.WaitGroup, svc plugin.HostServices) (plugin.ScriptPlugin, error) {
	defer wg.Done()

	logger := svc.Logger()

	initState := &instance.State{
		ActiveMode:     instance.Mode_MODE_STOPPED,
		RequestedMode:  instance.Mode_MODE_STOPPED,
		RequestedOn:    timestamppb.Now(),
		TransitionedOn: timestamppb.Now(),
	}
	initReq := &instance.ControlRequest{RequestedMode: instance.Mode_MODE_STOPPED}

	psp := plugin.NewPullScriptPlugin(initState, initReq, svc, nil, nil)

	psp.UpdateState(func(state *instance.State, verbose *instance.VerboseState) (plugin.UpdateType, error) {
		state.Tags = &config.TagSet{Tags: []*config.Tag{{Key: "description", Value: "Keep one AGV moving between waypoints based on idle position"}}}
		return plugin.UpdateTypeIncludesCore, nil
	})

	s := &script{
		cfg:      cfg,
		svc:      svc,
		psp:      psp,
		eidNs:    svc.EidNs(),
		leasedTo: svc.MyScriptId(),
		logger:   logger,
	}

	seqCfg := plugin.SequencerConfig[*script]{
		Steps: []*plugin.SequencerStep[*script]{
			{
				Name:        "wait_for_agv_idle",
				Description: "Wait for AGV to stop moving",
				Stages: []*plugin.SequencerStepStage[*script]{
					{
						Name: "wait_for_agv_idle",
						Op: func(opCtx context.Context, sc *script) error {
							return sc.waitForAgvIdle(opCtx)
						},
					},
				},
				Cancel: releaseMyLeasesForCancelFabric,
			},
			{
				Name:        "check_lease",
				Description: "Check if we have a lease on agv we want to move",
				Stages: []*plugin.SequencerStepStage[*script]{
					conditionalAgvLeased("get_lease", "move_agv"),
				},
			},
			{
				Name:        "get_lease",
				Description: "lease agv 003",
				Stages: []*plugin.SequencerStepStage[*script]{
					getAgvLeaseStageFabric(agv.AgvId(cfg.AgvName)),
				},
			},
			{
				Name:        "move_agv",
				Description: "Make the AGV move",
				Stages: []*plugin.SequencerStepStage[*script]{
					{
						Name: "move_agv",
						Op: func(opCtx context.Context, sc *script) error {
							wpToMoveTo := s.cfg.LoopStartWaypoint
							// we know we have state alread as otherwise we would not come this far...
							if s.agvControlStateTracker.Property().Property.GetCurrentWaypointId() == wpToMoveTo {
								wpToMoveTo = s.cfg.LoopEndWaypoint
							}
							return sc.requestMoveAGVJob(opCtx, wpToMoveTo)
						},
					},
				},
				Cancel: releaseMyLeasesForCancelFabric,
			},
		},
		Iterations: plugin.IterateForever,
	}

	seq, err := plugin.NewSequencer(seqCfg, psp, svc)
	if err != nil {
		return nil, fmt.Errorf("failed to create sequencer: %w", err)
	}
	s.seq = seq

	bo := retry.DefaultExponentialBackoffConfig().MustToBackoff()
	wg.Add(1)
	tracker, err := agvmgrsdk.NewTrackAgvControlState(
		ctx, wg, svc.FabricClient(), eidns.NewAgvEid(s.eidNs, s.cfg.AgvName), bo)
	if err != nil {
		return nil, err
	}
	s.agvControlStateTracker = tracker

	wg.Add(1)
	go seq.Runner(ctx, wg, s)

	logger.Info("dynamic agv idle mover configured", zap.String("agv", cfg.AgvName), zap.String("idle_wp", cfg.LoopStartWaypoint), zap.String("other_wp", cfg.LoopEndWaypoint))

	return psp, nil
}

func (s *script) requestMoveAGVJob(ctx context.Context, locNodeID string) error {
	s.logger.Debug("requesting agv move job", zap.String("loc_node_id", locNodeID))

	origCr := access.NewCommandRequest()
	reqParams := &agvmgrpb.OperateAgvRequest{
		CommandRequest: origCr,
		Command: &agvmgrpb.AgvCommand{
			WaypointId: locNodeID,
		},
		Requestor: s.leasedTo,
	}
	target := eidns.NewAgvEid(s.eidNs, s.cfg.AgvName)
	req, err := agvmgrsdk.OperateLeasedAgvRequest(ctx, s.svc.FabricClient(), reqParams, access.RequestWithTarget(target))
	if err != nil {
		return fmt.Errorf("requesting agv move operation: %w", err)
	}

	resp, err := req.Await(ctx)
	if err != nil {
		return fmt.Errorf("awaiting response for agv move operation: %w", err)
	}

	if resp == nil || resp.Response == nil {
		return errors.New("agv move operation failed on await response for request")
	}

	cr := resp.Response.GetCommandResponse()
	if cr.GetOutcome() == commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_FAILURE {
		err := errors.New(cr.GetDescription())
		if resp.Response.GetResponseCode() == agvmgrpb.OpResponseCode_OP_RESPONSE_CODE_AGV_NOT_LEASED {
			// We appear to have lost out lease. This probably means an operator intervened to take control. Losing the lease
			// means we need to start our cycle from scratch so we can reaquire if/when available.
			err = fmt.Errorf("%s no longer holds lease for %s: %v", s.leasedTo, target.String(), err)
			s.logger.Error("failed to operate agv", zap.Error(err))
			return plugin.NewErrRestartScriptCycle(err)
		}
		s.logger.Error("failed to operate agv, response included an error", zap.Error(err))
		return err //retry
	}

	// We have successfully sent a command to the AGV. Let's wait till we see our command in AGV control state or timeout.
	s.waitingOnJob = origCr.GetId()
	return s.waitForCommandInAgvControlState(ctx, s.waitingOnJob)
}

// waitForCommandInAgvControlState will wait for the command we sent to the AGV to appear in the AGV control state or timeout.
func (s *script) waitForCommandInAgvControlState(ctx context.Context, id string) error {
	first := true
	maxWait := time.Second * 2
	ctxWithMaxDuration, cancel := context.WithTimeout(ctx, maxWait)
	defer cancel()

	acs, _ := s.agvControlStateTracker.State()
	for ctxWithMaxDuration.Err() == nil {
		if !first {
			// stop and wait for next update
			acs, _ = s.agvControlStateTracker.WaitForUpdate(ctxWithMaxDuration)
		}
		first = false

		if acs == nil {
			return plugin.NewErrRestartScriptCycle(fmt.Errorf("job %s failed waiting to see our command reflected in agv control, unexpected missing state", id))
		}

		if commandInProgress(acs, id) {
			return nil
		}
	}

	return plugin.NewErrRestartScriptCycle(fmt.Errorf("job %s failed waiting to see our command reflected in agv control", id))
}

func (s *script) waitForAgvIdle(ctx context.Context) error {
	s.logger.Debug("waiting for agv to be idle")

	first := true
	ctrlState, _ := s.agvControlStateTracker.State()
	for ctx.Err() == nil {
		if !first {
			// wait for subsequent update from AGV controller
			ctrlState, _ = s.agvControlStateTracker.WaitForUpdate(ctx)
		}
		first = false
		if ctrlState == nil {
			// we are not seeing any state at all... we will wait for next update.
			s.updateActiveStepWithReason(plugin.StepReason{
				Reason: "no_active_state",
			}, instance.StepStatus_STEP_STATUS_EXECUTING, false)
			continue // wait for next update or being stopped
		}
		// ok, we have some state to work with...
		if ctrlState.GetActiveCommand() != nil {
			s.waitingOnJob = ctrlState.GetActiveCommand().GetCommandInstance().GetRequest().GetId()
			// we are not seeing any state at all... we will wait for next update.
			s.updateActiveStepWithReason(plugin.StepReason{
				Reason: "agv_busy_with_active_command",
			}, instance.StepStatus_STEP_STATUS_EXECUTING, false)
			// wait for next update
			continue
		}

		// we have a idle agv... time to grab it.
		return nil
	}

	return nil
}

func releaseMyLeasesForCancelFabric(ctx context.Context, s *script, err error) {
	releaseMyAgvLeaseFabric(ctx, s, agv.AgvId(s.cfg.AgvName))
}

// releases a lease for a specific AGV. This can be called on cancellation or at the end of an operation.
func releaseMyAgvLeaseFabric(ctx context.Context, s *script, agvId agv.AgvId) error {

	// lease requests are sent tot he AgvManager
	targetId := eidns.NewAgvManagerEid(s.svc.EidNs())
	// Fabric client - this will allow us to access fabric.
	client := s.svc.FabricClient()
	// leasedTo me
	leasedTo := s.leasedTo

	request := &agvmgrpb.ReturnLeaseAgvRequest{
		CommandRequest: access.NewCommandRequest(),
		AgvId:          agvId.String(),
		LeasedTo:       leasedTo,
	}

	result, err := agv_manager.ReturnLeaseOnAgvRequest(ctx, client, request, access.RequestWithTarget(targetId))
	if err != nil {
		return err
	}

	response, err := result.Await(ctx)
	if err != nil {
		return err
	}

	r := response.Response.GetCommandResponse()
	if r.GetOutcome() != commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_ACCEPTED {
		err := fmt.Errorf("failed to release lease for %s: %s", agvId.String(), r.GetOutcome().String())
		// If we were not leases as expected, we are fine... because when we start out cycle we will either
		// release and acquire or acquire as necessary.
		return plugin.NewErrRestartScriptStep(err)
	}

	return nil
}

// getAgvLeaseStageFabeic creates a sequencer step stage that leases a specific agv over fabric
func getAgvLeaseStageFabric(agvId agv.AgvId) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "leaseAgv",
		Op: func(ctx context.Context, s *script) error {

			// lease requests are sent tot he AgvManager
			targetId := eidns.NewAgvManagerEid(s.eidNs)
			// Fabric client - this will allow us to access fabric.
			client := s.svc.FabricClient()
			// leasedTo me
			leasedTo := s.leasedTo

			req := &agvmgrpb.LeaseAgvRequest{
				LeasedTo:       leasedTo,
				CommandRequest: access.NewCommandRequest(),
				MandatedAgvIds: []string{agvId.String()},
			}
			result, err := agv_manager.GetLeaseOnAgvRequest(
				ctx,
				client,
				req,
				access.RequestWithTarget(targetId))
			if err != nil {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv on request %s: %w", agvId.String(), err))
			}

			response, err := result.Await(ctx)
			if err != nil {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv on await %s: %w", agvId.String(), err))
			}

			r := response.Response
			cr := r.GetCommandResponse()
			if cr.GetOutcome() != commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_ACCEPTED {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv %s, %s", agvId.String(), cr.GetDescription()))
			}

			if r.GetAgvId() == "" {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv %s, no agv id returned", agvId.String()))
			}

			// for reporting purposes only, we also record the AGV in the active job
			s.psp.UpdateFirstActiveJob(func(j *instance.StepReport) (plugin.UpdateType, error) {
				j.EntityIds = append(
					j.EntityIds, s.eidNs.NewEntityKindAndName(config.EntityKind_ENTITY_KIND_AGV, agvId.String()))
				// defer immediate update given we're about to return nil closing the step (which will automatically update)
				return plugin.UpdateTypeNone, nil
			})

			return nil
		},
	}
}

// conditionalAgvLeased checks if tracked agv is leased by me and goes to next stage appropriately
func conditionalAgvLeased(stepToGetLease, stepIdLeased string) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "conditionalAgvLeased",
		Op: func(ctx context.Context, s *script) error {

			// leasedTo me
			leasedTo := s.leasedTo

			first := true
			ctrlState, _ := s.agvControlStateTracker.State()
			for ctx.Err() == nil {
				if !first {
					// wait for subsequent update from AGV controller
					ctrlState, _ = s.agvControlStateTracker.WaitForUpdate(ctx)
				}
				first = false
				if ctrlState == nil {
					// we are not seeing any state at all... we will wait for next update.
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason: "no_active_state",
					}, instance.StepStatus_STEP_STATUS_EXECUTING, false)
					continue // wait for next update or being stopped
				}

				if lease := ctrlState.GetLease(); lease != nil && lease.GetTo() == leasedTo {
					// we have the lease, move to the appropriate next step, and also make sure we show up in the leased
					// adjs we are tracking.
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason:  "leased",
						Context: map[string]any{"next_step": stepIdLeased},
					}, instance.StepStatus_STEP_STATUS_EXECUTING, true)
					return plugin.NewErrRestartScriptStepByName(fmt.Errorf("AGV is leased to me, skip to next step"), stepIdLeased, s.seq)
				} else {
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason:  "not_leased",
						Context: map[string]any{"next_step": stepToGetLease},
					}, instance.StepStatus_STEP_STATUS_EXECUTING, true)
					return plugin.NewErrRestartScriptStepByName(fmt.Errorf("agv not leased to me, skip to load step"), stepToGetLease, s.seq)
				}
			}

			return ctx.Err()
		},
	}
}

// update the active step status of the script.
func (s *script) updateActiveStepWithReason(reason plugin.StepReason, status instance.StepStatus, deferNotification bool) {
	reasonStr := reason.String()
	s.psp.UpdateState(func(state *instance.State, detailed *instance.VerboseState) (plugin.UpdateType, error) {

		fs := detailed.ActiveSteps[0]
		if fs != nil {
			update := false

			if deferNotification || fs.Status != status || fs.Reason != reasonStr {
				fs.Status = status
				fs.Reason = reasonStr
				update = true
			}

			if s.waitingOnJob != "" {
				fs.JobIds = []string{s.waitingOnJob}
				update = true // no need to dampen, set to true even if job was there already
			}

			if update && !deferNotification {
				return plugin.UpdateTypeOnlyDetailed, nil
			}
		}
		return plugin.UpdateTypeNone, nil
	})
}

// getCommandInstance finds the command record for a give instance.
func commandInProgress(acs *agvmgrpb.AgvControlState, commandId string) bool {
	if acs.ActiveCommand != nil &&
		acs.GetActiveCommand().GetCommandInstance().GetRequest().GetId() == commandId {
		return true
	}

	for _, cr := range acs.GetRecentCommands() {
		if cr.GetCommandInstance().GetRequest().GetId() == commandId {
			return true
		}
	}
	return false
}

func init() {
	defaultCfg := &Config{
		AgvName:           "300",
		LoopStartWaypoint: "wp8",
		LoopEndWaypoint:   "wp5",
	}
	plugin.RegisterPlugin("demo_loop", defaultCfg.Configure)
}

package dynamic

import (
	"context"
	"errors"
	"fmt"
	"sync"
	"time"

	"github.com/Kerrigan-Automation/overmind/public/lib/eidns"
	access "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/conveyance/mobile/agv_manager"
	agvmgrsdk "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/conveyance/mobile/agv_manager"
	agvmgrpb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/conveyance/mobile/agv_manager"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/escript/instance"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/commands"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/config"
	agv "github.com/Kerrigan-Automation/overmind/public/lib/fm/agv"
	"github.com/Kerrigan-Automation/overmind/public/lib/retry"
	plugin "github.com/Kerrigan-Automation/overmind/public/lib/script/go_plugin"
	"go.uber.org/zap"
	"google.golang.org/protobuf/types/known/timestamppb"
)

type Config struct {
	AgvName           string
	LoopStartWaypoint string
	LoopEndWaypoint   string
	IdleDelay         time.Duration
}

type script struct {
	cfg                    *Config
	svc                    plugin.HostServices
	psp                    *plugin.PullScriptPlugin
	eidNs                  *eidns.EidNsManager
	leasedTo               string
	seq                    *plugin.Sequencer[*script]
	logger                 *zap.Logger
	agvControlStateTracker *agvmgrsdk.TrackedAgvControlState
	// for diagnostics only...
	waitingOnJob string
}

func (cfg *Config) Configure(ctx context.Context, wg *sync.WaitGroup, svc plugin.HostServices) (plugin.ScriptPlugin, error) {
	defer wg.Done()

	logger := svc.Logger()

	initState := &instance.State{
		ActiveMode:     instance.Mode_MODE_STOPPED,
		RequestedMode:  instance.Mode_MODE_STOPPED,
		RequestedOn:    timestamppb.Now(),
		TransitionedOn: timestamppb.Now(),
	}
	initReq := &instance.ControlRequest{RequestedMode: instance.Mode_MODE_STOPPED}

	psp := plugin.NewPullScriptPlugin(initState, initReq, svc, nil, nil)

	psp.UpdateState(func(state *instance.State, verbose *instance.VerboseState) (plugin.UpdateType, error) {
		state.Tags = &config.TagSet{Tags: []*config.Tag{{Key: "description", Value: "Keep one AGV moving between waypoints based on idle position"}}}
		return plugin.UpdateTypeIncludesCore, nil
	})

	s := &script{
		cfg:      cfg,
		svc:      svc,
		psp:      psp,
		eidNs:    svc.EidNs(),
		leasedTo: svc.MyScriptId(),
		logger:   logger,
	}

	seqCfg := plugin.SequencerConfig[*script]{
		Steps: []*plugin.SequencerStep[*script]{
			{
				Name:        "wait_for_agv_idle",
				Description: "Wait for AGV to stop moving",
				Stages: []*plugin.SequencerStepStage[*script]{
					{
						Name: "wait_for_agv_idle",
						Op: func(opCtx context.Context, sc *script) error {
							return sc.waitForAgvIdle(opCtx)
						},
					},
				},
				Cancel: releaseMyLeasesForCancelFabric,
			},
			{
				Name:        "wait_for_MES_next_cycle_request",
				Description: "If at wp8, release lease and wait to simulate MES delay",
				Stages: []*plugin.SequencerStepStage[*script]{
					{
						Name: "conditional_delay",
						Op: func(opCtx context.Context, sc *script) error {
							currentWp := sc.agvControlStateTracker.Property().Property.GetCurrentWaypointId()
							if currentWp == sc.cfg.LoopStartWaypoint {
								sc.logger.Info("AGV at loop start waypoint, releasing lease and waiting", zap.Duration("delay", sc.cfg.IdleDelay))

								// Release the lease so others can grab it
								err := releaseMyAgvLeaseFabric(opCtx, sc, agv.AgvId(sc.cfg.AgvName))
								if err != nil {
									sc.logger.Warn("Failed to release lease before delay", zap.Error(err))
								}

								// Update step status
								sc.updateActiveStepWithReason(plugin.StepReason{
									Reason: "waiting_for_MES_next_cycle_request",
								}, instance.StepStatus_STEP_STATUS_EXECUTING, false)

								// Sleep for the delay duration
								select {
								case <-time.After(sc.cfg.IdleDelay):
								case <-opCtx.Done():
									return opCtx.Err()
								}
							}
							return nil
						},
					},
				},
			},
			{
				Name:        "check_lease",
				Description: "Check if we have a lease on agv we want to move",
				Stages: []*plugin.SequencerStepStage[*script]{
					conditionalAgvLeased("get_lease", "move_agv"),
				},
			},
			{
				Name:        "get_lease",
				Description: "lease agv 003",
				Stages: []*plugin.SequencerStepStage[*script]{
					getAgvLeaseStageFabric(agv.AgvId(cfg.AgvName)),
				},
			},
			{
				Name:        "move_agv",
				Description: "Make the AGV move",
				Stages: []*plugin.SequencerStepStage[*script]{
					{
						Name: "move_agv",
						Op: func(opCtx context.Context, sc *script) error {
							wpToMoveTo := s.cfg.LoopStartWaypoint
							// we know we have state alread as otherwise we would not come this far...
							if s.agvControlStateTracker.Property().Property.GetCurrentWaypointId() == wpToMoveTo {
								wpToMoveTo = s.cfg.LoopEndWaypoint
							}
							return sc.requestMoveAGVJob(opCtx, wpToMoveTo)
						},
					},
				},
				Cancel: releaseMyLeasesForCancelFabric,
			},
		},
		Iterations: plugin.IterateForever,
	}

	seq, err := plugin.NewSequencer(seqCfg, psp, svc)
	if err != nil {
		return nil, fmt.Errorf("failed to create sequencer: %w", err)
	}
	s.seq = seq

	bo := retry.DefaultExponentialBackoffConfig().MustToBackoff()
	wg.Add(1)
	tracker, err := agvmgrsdk.NewTrackAgvControlState(
		ctx, wg, svc.FabricClient(), eidns.NewAgvEid(s.eidNs, s.cfg.AgvName), bo)
	if err != nil {
		return nil, err
	}
	s.agvControlStateTracker = tracker

	wg.Add(1)
	go seq.Runner(ctx, wg, s)

	logger.Info("dynamic agv idle mover configured", zap.String("agv", cfg.AgvName), zap.String("idle_wp", cfg.LoopStartWaypoint), zap.String("other_wp", cfg.LoopEndWaypoint))

	return psp, nil
}

func (s *script) requestMoveAGVJob(ctx context.Context, locNodeID string) error {
	s.logger.Debug("requesting agv move job", zap.String("loc_node_id", locNodeID))

	origCr := access.NewCommandRequest()
	reqParams := &agvmgrpb.OperateAgvRequest{
		CommandRequest: origCr,
		Command: &agvmgrpb.AgvCommand{
			WaypointId: locNodeID,
		},
		Requestor: s.leasedTo,
	}
	target := eidns.NewAgvEid(s.eidNs, s.cfg.AgvName)
	req, err := agvmgrsdk.OperateLeasedAgvRequest(ctx, s.svc.FabricClient(), reqParams, access.RequestWithTarget(target))
	if err != nil {
		return fmt.Errorf("requesting agv move operation: %w", err)
	}

	resp, err := req.Await(ctx)
	if err != nil {
		return fmt.Errorf("awaiting response for agv move operation: %w", err)
	}

	if resp == nil || resp.Response == nil {
		return errors.New("agv move operation failed on await response for request")
	}

	cr := resp.Response.GetCommandResponse()
	if cr.GetOutcome() == commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_FAILURE {
		err := errors.New(cr.GetDescription())
		if resp.Response.GetResponseCode() == agvmgrpb.OpResponseCode_OP_RESPONSE_CODE_AGV_NOT_LEASED {
			// We appear to have lost out lease. This probably means an operator intervened to take control. Losing the lease
			// means we need to start our cycle from scratch so we can reaquire if/when available.
			err = fmt.Errorf("%s no longer holds lease for %s: %v", s.leasedTo, target.String(), err)
			s.logger.Error("failed to operate agv", zap.Error(err))
			return plugin.NewErrRestartScriptCycle(err)
		}
		s.logger.Error("failed to operate agv, response included an error", zap.Error(err))
		return err //retry
	}

	// We have successfully sent a command to the AGV. Let's wait till we see our command in AGV control state or timeout.
	s.waitingOnJob = origCr.GetId()
	return s.waitForCommandInAgvControlState(ctx, s.waitingOnJob)
}

// waitForCommandInAgvControlState will wait for the command we sent to the AGV to appear in the AGV control state or timeout.
func (s *script) waitForCommandInAgvControlState(ctx context.Context, id string) error {
	first := true
	maxWait := time.Second * 2
	ctxWithMaxDuration, cancel := context.WithTimeout(ctx, maxWait)
	defer cancel()

	acs, _ := s.agvControlStateTracker.State()
	for ctxWithMaxDuration.Err() == nil {
		if !first {
			// stop and wait for next update
			acs, _ = s.agvControlStateTracker.WaitForUpdate(ctxWithMaxDuration)
		}
		first = false

		if acs == nil {
			return plugin.NewErrRestartScriptCycle(fmt.Errorf("job %s failed waiting to see our command reflected in agv control, unexpected missing state", id))
		}

		if commandInProgress(acs, id) {
			return nil
		}
	}

	return plugin.NewErrRestartScriptCycle(fmt.Errorf("job %s failed waiting to see our command reflected in agv control", id))
}

func (s *script) waitForAgvIdle(ctx context.Context) error {
	s.logger.Debug("waiting for agv to be idle")

	first := true
	ctrlState, _ := s.agvControlStateTracker.State()
	for ctx.Err() == nil {
		if !first {
			// wait for subsequent update from AGV controller
			ctrlState, _ = s.agvControlStateTracker.WaitForUpdate(ctx)
		}
		first = false
		if ctrlState == nil {
			// we are not seeing any state at all... we will wait for next update.
			s.updateActiveStepWithReason(plugin.StepReason{
				Reason: "no_active_state",
			}, instance.StepStatus_STEP_STATUS_EXECUTING, false)
			continue // wait for next update or being stopped
		}
		// ok, we have some state to work with...
		if ctrlState.GetActiveCommand() != nil {
			s.waitingOnJob = ctrlState.GetActiveCommand().GetCommandInstance().GetRequest().GetId()
			// we are not seeing any state at all... we will wait for next update.
			s.updateActiveStepWithReason(plugin.StepReason{
				Reason: "agv_busy_with_active_command",
			}, instance.StepStatus_STEP_STATUS_EXECUTING, false)
			// wait for next update
			continue
		}

		// we have a idle agv... time to grab it.
		return nil
	}

	return nil
}

func releaseMyLeasesForCancelFabric(ctx context.Context, s *script, err error) {
	releaseMyAgvLeaseFabric(ctx, s, agv.AgvId(s.cfg.AgvName))
}

// releases a lease for a specific AGV. This can be called on cancellation or at the end of an operation.
func releaseMyAgvLeaseFabric(ctx context.Context, s *script, agvId agv.AgvId) error {

	// lease requests are sent tot he AgvManager
	targetId := eidns.NewAgvManagerEid(s.svc.EidNs())
	// Fabric client - this will allow us to access fabric.
	client := s.svc.FabricClient()
	// leasedTo me
	leasedTo := s.leasedTo

	request := &agvmgrpb.ReturnLeaseAgvRequest{
		CommandRequest: access.NewCommandRequest(),
		AgvId:          agvId.String(),
		LeasedTo:       leasedTo,
	}

	result, err := agv_manager.ReturnLeaseOnAgvRequest(ctx, client, request, access.RequestWithTarget(targetId))
	if err != nil {
		return err
	}

	response, err := result.Await(ctx)
	if err != nil {
		return err
	}

	r := response.Response.GetCommandResponse()
	if r.GetOutcome() != commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_ACCEPTED {
		err := fmt.Errorf("failed to release lease for %s: %s", agvId.String(), r.GetOutcome().String())
		// If we were not leases as expected, we are fine... because when we start out cycle we will either
		// release and acquire or acquire as necessary.
		return plugin.NewErrRestartScriptStep(err)
	}

	return nil
}

// getAgvLeaseStageFabeic creates a sequencer step stage that leases a specific agv over fabric
func getAgvLeaseStageFabric(agvId agv.AgvId) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "leaseAgv",
		Op: func(ctx context.Context, s *script) error {

			// lease requests are sent tot he AgvManager
			targetId := eidns.NewAgvManagerEid(s.eidNs)
			// Fabric client - this will allow us to access fabric.
			client := s.svc.FabricClient()
			// leasedTo me
			leasedTo := s.leasedTo

			req := &agvmgrpb.LeaseAgvRequest{
				LeasedTo:       leasedTo,
				CommandRequest: access.NewCommandRequest(),
				MandatedAgvIds: []string{agvId.String()},
			}
			result, err := agv_manager.GetLeaseOnAgvRequest(
				ctx,
				client,
				req,
				access.RequestWithTarget(targetId))
			if err != nil {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv on request %s: %w", agvId.String(), err))
			}

			response, err := result.Await(ctx)
			if err != nil {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv on await %s: %w", agvId.String(), err))
			}

			r := response.Response
			cr := r.GetCommandResponse()
			if cr.GetOutcome() != commands.CommandResponseOutcome_COMMAND_RESPONSE_OUTCOME_ACCEPTED {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv %s, %s", agvId.String(), cr.GetDescription()))
			}

			if r.GetAgvId() == "" {
				return plugin.NewErrRestartScriptCycle(fmt.Errorf("failed to lease agv %s, no agv id returned", agvId.String()))
			}

			// for reporting purposes only, we also record the AGV in the active job
			s.psp.UpdateFirstActiveJob(func(j *instance.StepReport) (plugin.UpdateType, error) {
				j.EntityIds = append(
					j.EntityIds, s.eidNs.NewEntityKindAndName(config.EntityKind_ENTITY_KIND_AGV, agvId.String()))
				// defer immediate update given we're about to return nil closing the step (which will automatically update)
				return plugin.UpdateTypeNone, nil
			})

			return nil
		},
	}
}

// conditionalAgvLeased checks if tracked agv is leased by me and goes to next stage appropriately
func conditionalAgvLeased(stepToGetLease, stepIdLeased string) *plugin.SequencerStepStage[*script] {
	return &plugin.SequencerStepStage[*script]{
		Name: "conditionalAgvLeased",
		Op: func(ctx context.Context, s *script) error {

			// leasedTo me
			leasedTo := s.leasedTo

			first := true
			ctrlState, _ := s.agvControlStateTracker.State()
			for ctx.Err() == nil {
				if !first {
					// wait for subsequent update from AGV controller
					ctrlState, _ = s.agvControlStateTracker.WaitForUpdate(ctx)
				}
				first = false
				if ctrlState == nil {
					// we are not seeing any state at all... we will wait for next update.
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason: "no_active_state",
					}, instance.StepStatus_STEP_STATUS_EXECUTING, false)
					continue // wait for next update or being stopped
				}

				if lease := ctrlState.GetLease(); lease != nil && lease.GetTo() == leasedTo {
					// we have the lease, move to the appropriate next step, and also make sure we show up in the leased
					// adjs we are tracking.
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason:  "leased",
						Context: map[string]any{"next_step": stepIdLeased},
					}, instance.StepStatus_STEP_STATUS_EXECUTING, true)
					return plugin.NewErrRestartScriptStepByName(fmt.Errorf("AGV is leased to me, skip to next step"), stepIdLeased, s.seq)
				} else {
					s.updateActiveStepWithReason(plugin.StepReason{
						Reason:  "not_leased",
						Context: map[string]any{"next_step": stepToGetLease},
					}, instance.StepStatus_STEP_STATUS_EXECUTING, true)
					return plugin.NewErrRestartScriptStepByName(fmt.Errorf("agv not leased to me, skip to load step"), stepToGetLease, s.seq)
				}
			}

			return ctx.Err()
		},
	}
}

// update the active step status of the script.
func (s *script) updateActiveStepWithReason(reason plugin.StepReason, status instance.StepStatus, deferNotification bool) {
	reasonStr := reason.String()
	s.psp.UpdateState(func(state *instance.State, detailed *instance.VerboseState) (plugin.UpdateType, error) {

		fs := detailed.ActiveSteps[0]
		if fs != nil {
			update := false

			if deferNotification || fs.Status != status || fs.Reason != reasonStr {
				fs.Status = status
				fs.Reason = reasonStr
				update = true
			}

			if s.waitingOnJob != "" {
				fs.JobIds = []string{s.waitingOnJob}
				update = true // no need to dampen, set to true even if job was there already
			}

			if update && !deferNotification {
				return plugin.UpdateTypeOnlyDetailed, nil
			}
		}
		return plugin.UpdateTypeNone, nil
	})
}

// getCommandInstance finds the command record for a give instance.
func commandInProgress(acs *agvmgrpb.AgvControlState, commandId string) bool {
	if acs.ActiveCommand != nil &&
		acs.GetActiveCommand().GetCommandInstance().GetRequest().GetId() == commandId {
		return true
	}

	for _, cr := range acs.GetRecentCommands() {
		if cr.GetCommandInstance().GetRequest().GetId() == commandId {
			return true
		}
	}
	return false
}

func init() {
	defaultCfg := &Config{
		AgvName:           "300",
		LoopStartWaypoint: "wp8",
		LoopEndWaypoint:   "wp5",
		IdleDelay:         5 * time.Second,
	}
	plugin.RegisterPlugin("demo_loop_mes", defaultCfg.Configure)
}

