package prov_trk_agv_battery_tray

import (
	common "github.com/Kerrigan-Automation/overmind/public/cmd/script/go_plugin/plugins/prov_trk_agv_common"
	trackpb "github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/conveyance/track"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/config"
	"github.com/Kerrigan-Automation/overmind/public/lib/fabric/access/go/generated/proto/meta/domain"
)

func ProvideTrackSpec() common.TrackSpec {
	return common.TrackSpec{
		Name:   "battery_tray_siasun_tk_trk",
		Config: getConfig(),
	}
}

func getConfig() *trackpb.TrackConfig {
	return &trackpb.TrackConfig{
		Metadata: &config.VersionedObjectMetadata{
			Name:        "battery_tray_siasun_tk_trk",
			Description: "Generated from DXF TrayRoute",
		},
		Origin:             &domain.Point{X: 0, Y: 0, Z: 0},
		ScaleFactor:        &domain.Point{X: 1, Y: 1, Z: 0},
		ProximityTolerance: 1,
		Nodes: []*trackpb.NodeConfig{
			{
				NodeId:      "gwp0001",
				Name:        "gwp0001",
				Description: "",
				Pose: &domain.Pose{
