files.script.go:
package prov_trk_agv_general_assembly

import (
	"context"
	"sync"

	common "github.com/Kerrigan-Automation/overmind/public/cmd/script/go_plugin/plugins/prov_trk_agv_common"
	plugin "github.com/Kerrigan-Automation/overmind/public/lib/script/go_plugin"
)

// Configure constructs the wrapper with Siasun make
func Configure(ctx context.Context, wg *sync.WaitGroup, svc plugin.HostServices) (plugin.ScriptPlugin, error) {
	return common.ConfigureWithTrackAndAgvs(ctx, wg, svc,
		ProvideTrackSpec,
		ProvideAgvSpec,
	)
}

// Register plugin at init time
func init() {
	_ = plugin.RegisterPlugin("prov_trk_agv_general_assembly", Configure)
}

