      "y": 0.07,
      "z": 0
    },
    "start_orientation": {
      "yaw": 0,
      "pitch": 0,
      "roll": 0
    },
    "server_listen_address": "localhost",
    "server_listen_port": ` + internalPortStr + `  }
}				
`),
					ProxyEndpoint: &agvpb.ProxyEndpoint{
						Host:         "localhost",
